'use strict';

/* ── PWA ──────────────────────────────────────────────────── */
document.getElementById('manifest-link').href = URL.createObjectURL(
new Blob([JSON.stringify({
name:'JhunForge',short_name:'JhunForge',display:'standalone',
background_color:'#0d1117',theme_color:'#0d1117',start_url:'./',
icons:[{src:"data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 64 64'%3E%3Crect width='64' height='64' fill='%230d1117'/%3E%3Crect x='16' y='16' width='32' height='32' fill='%233fb950'/%3E%3C/svg%3E",sizes:'64x64',type:'image/svg+xml'}]
})],{type:'application/json'})
);

/* ── Canvas refs ──────────────────────────────────────────── */
const MC  = document.getElementById('main-canvas');
const MCX = MC.getContext('2d', {willReadFrequently:true});
const GC  = document.getElementById('grid-canvas');
const GCX = GC.getContext('2d');

/* ── State ────────────────────────────────────────────────── */
const S = {
zip: null, packName: '',
files: [],           // ALL files: {name, path, data:Uint8Array, modified, type}
current: null,       // currently open file object
currentKind: null,   // 'image' | 'text' | 'binary'
zoom: 8, tool: 'pencil',
color: {r:63,g:185,b:80,a:255},
drawing: false,
history: [], hIdx: -1,
originals: new Map(),
layers: [],          // layer objects
activeLayerIdx: 0,   // index into S.layers
};

/* ── Multi-pack state ─────────────────────────────────────── */
let PACKS = [];        // array of saved pack snapshots
let activePackIdx = -1;

/* ── Audio state (declared here so setMode can reference it) ─ */
const AUD = {
ctx: null, buffer: null, source: null, gainNode: null,
startedAt: 0, pausedAt: 0,
playing: false, looping: false,
pitch: 0, volume: 1.0, rate: 1.0,
rafId: null, file: null,
};

/* ── File type detection ─────────────────────────────────── */
const IMG_EXTS   = ['png','jpg','jpeg','tga'];
const TEXT_EXTS  = ['json','jsonc','lang','txt','mcfunction','molang','material','fsh','vsh','glsl','js','ts','py','xml','html','css','md','properties','ini','cfg'];
const AUDIO_EXTS = ['ogg','mp3','wav','flac','m4a','aac','opus','fsb'];

function extOf(path) { return path.split('.').pop().toLowerCase(); }

function kindOf(path) {
const ext = extOf(path);
if (IMG_EXTS.includes(ext))   return 'image';
if (TEXT_EXTS.includes(ext))  return 'text';
if (AUDIO_EXTS.includes(ext)) return 'audio';
return 'binary';
}

function iconOf(path, isDir=false) {
if (isDir) return '▶';
const ext = extOf(path);
const map = {
png:'🖼',jpg:'🖼',jpeg:'🖼',tga:'🖼',
json:'{ }',jsonc:'{ }',
lang:'🌐',txt:'📄',
mcfunction:'⚙',molang:'⚙',material:'🎨',
fsh:'🔆',vsh:'🔆',glsl:'🔆',
ogg:'🔊',mp3:'🔊',wav:'🔊',flac:'🔊',m4a:'🔊',aac:'🔊',opus:'🔊',fsb:'🔊',
ttf:'Aa',otf:'Aa',
mcpack:'📦',zip:'📦',
};
return map[ext] || '📄';
}

function colorOf(path) {
const ext = extOf(path);
if (IMG_EXTS.includes(ext))  return 'var(--blue)';
if (['json','jsonc'].includes(ext)) return 'var(--gold)';
if (ext === 'lang') return 'var(--purple)';
if (['fsh','vsh','glsl','material'].includes(ext)) return '#e8795a';
if (AUDIO_EXTS.includes(ext)) return '#a78bfa';
if (ext === 'mcfunction') return 'var(--green)';
return 'var(--muted)';
}

function fmtSize(bytes) {
if (bytes < 1024) return bytes + ' B';
if (bytes < 1024*1024) return (bytes/1024).toFixed(1) + ' KB';
return (bytes/(1024*1024)).toFixed(2) + ' MB';
}

/* ── HTML escape helper (prevents XSS from crafted zip content) ── */
function esc(s) {
  return String(s)
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;');
}

/* ── Toast / modal ────────────────────────────────────────── */
function toast(msg, type='i', ms=3200) {
const d = document.createElement('div');
d.className = `toast ${type}`;
const icon = document.createElement('span');
icon.textContent = {s:'✅',e:'❌',i:'ℹ️'}[type]||'';
const text = document.createElement('span');
text.textContent = msg;
d.appendChild(icon);
d.appendChild(text);
document.getElementById('toasts').appendChild(d);
setTimeout(()=>d.remove(), ms);
}

function showConfirm(title, body) {
return new Promise(r => {
document.getElementById('modal-title').textContent = title;
document.getElementById('modal-body').textContent  = body;
document.getElementById('modal-bg').classList.remove('off');
const close = () => document.getElementById('modal-bg').classList.add('off');
document.getElementById('modal-yes').onclick = ()=>{close();r(true);};
document.getElementById('modal-no') .onclick = ()=>{close();r(false);};
});
}

/* ── UI state machine ─────────────────────────────────────── */
// mode: 'load' | 'hint' | 'image' | 'text' | 'audio' | 'binary'
function setMode(mode) {
const ovLoad  = document.getElementById('ov-load');
const ovHint  = document.getElementById('ov-hint');
const ca      = document.getElementById('canvas-area');
const ta      = document.getElementById('text-area');
const aa      = document.getElementById('audio-area');
const tbarImg = document.getElementById('toolbar-img');
const tbarTxt = document.getElementById('toolbar-txt');

ovLoad.classList.toggle('off', mode !== 'load');
ovHint.classList.toggle('off', mode !== 'hint');
ca.style.display      = mode === 'image'  ? 'block' : 'none';
ta.style.display      = mode === 'text'   ? 'flex'  : 'none';
aa.style.display      = mode === 'audio'  ? 'flex'  : 'none';
tbarImg.style.display = mode === 'image'  ? 'flex'  : 'none';
tbarTxt.style.display = mode === 'text'   ? 'flex'  : 'none';
document.getElementById('cursor-info').style.display = mode==='image'?'block':'none';

// stop audio when leaving audio mode
if (mode !== 'audio' && typeof audioStop === 'function') audioStop();

// right panel sections
const imgOnly = document.querySelectorAll('.img-only');
imgOnly.forEach(el => el.classList.toggle('hidden', mode !== 'image'));
}
setMode('load');

/* ── Open a file ──────────────────────────────────────────── */
async function openFile(f) {
S.current = f;
S.currentKind = kindOf(f.path);
highlightActive();
updateFileInfo();

if (S.currentKind === 'image') {
await openImage(f);
} else if (S.currentKind === 'text') {
openText(f);
} else if (S.currentKind === 'audio') {
await openAudio(f);
} else {
openBinary(f);
}
}
async function loadZip(file, newTab=false) {
toast('Reading pack…','i',1800);
try {
const zip  = await JSZip.loadAsync(file);
// Multi-pack: if newTab, a blank slot is already pushed by openNewPackTab.
// If replacing current tab, just reuse activePackIdx slot.
if (!newTab && PACKS.length === 0) {
  PACKS.push(emptyPackSlot());
  activePackIdx = 0;
}
S.zip      = zip;
S.packName = file.name.replace(/\.(zip|mcpack)$/i,'');
S.files    = [];
S.originals.clear();
S.current  = null;
document.getElementById('btn-export').disabled = false;
document.getElementById('btn-export-arrow').disabled = false;

// Scan all entry paths for XSS patterns before loading anything
let xssDetected = false;
zip.forEach((relPath, entry) => {
  if (entry.dir) return;
  const norm = relPath.replace(/\\/g, "/");
  if (/<|>|javascript:|onerror|onload|onmouseover|onclick|script|alert\s*\(|eval\s*\(|document\.|window\./i.test(norm)) {
    xssDetected = true;
  }
});
if (xssDetected) {
  toast("bro??", "e", 4000);
  if (newTab) { PACKS.pop(); activePackIdx = Math.max(0, PACKS.length - 1); switchToPack(activePackIdx); }
  return;
}

const jobs = [];
zip.forEach((relPath, entry) => {
if (entry.dir) return;
const norm = relPath.replace(/\\/g,'/');
if (/\/__MACOSX\//.test(norm) || /\/\./.test(norm)) return;
if (norm.includes('../') || norm.startsWith('/')) return; // block path traversal
const name = norm.split('/').pop();
const type = kindOf(norm);
jobs.push(
entry.async('uint8array')
.then(data => S.files.push({name, path:norm, data, modified:false, type}))
.catch(()=>{})
);
});

await Promise.all(jobs);
S.files.sort((a,b)=>a.path.localeCompare(b.path));

if (!S.files.length) { toast('No files found in this pack.','e',4000); return; }

toast(`${S.files.length} files loaded from ${S.packName}`,'s',3500);
document.getElementById('sidebar-actions').classList.add('visible');
setMode('hint');
saveCurrentPack();
renderPackTabs();
renderTree();
} catch(e) {
toast('Failed to load: '+e.message,'e',5000);
console.error('[JhunForge] loadZip:',e);
}
}

/* ── Tree rendering ───────────────────────────────────────── */
/* ── Multi-pack helpers ───────────────────────────────────── */
function emptyPackSlot() {
  return { zip: null, packName: '', files: [], originals: new Map(), current: null, currentKind: null, history: [], hIdx: -1, layers: [], activeLayerIdx: 0, openFolders: new Set() };
}

function saveCurrentPack() {
  if (activePackIdx < 0) return;
  const p = PACKS[activePackIdx];
  p.zip            = S.zip;
  p.packName       = S.packName;
  p.files          = S.files;
  p.originals      = S.originals;
  p.current        = S.current;
  p.currentKind    = S.currentKind;
  p.history        = S.history;
  p.hIdx           = S.hIdx;
  p.layers         = S.layers;
  p.activeLayerIdx = S.activeLayerIdx;
  p.openFolders    = getOpenFolders();
}

async function switchToPack(idx) {
  if (idx === activePackIdx) return;
  // Flush any unsaved canvas/text edits into S.current.data before leaving
  if (S.current && S.currentKind === 'image') {
    await new Promise(res => {
      const fc = layerFlatCanvas();
      fc.toBlob(blob => blob.arrayBuffer().then(ab => {
        S.current.data = new Uint8Array(ab);
        S.current.modified = true;
        res();
      }), 'image/png');
    });
  } else if (S.current && S.currentKind === 'text') {
    S.current.data = new TextEncoder().encode(document.getElementById('text-editor').value);
    S.current.modified = true;
  }
  saveCurrentPack();
  activePackIdx = idx;
  const p = PACKS[idx];
  S.zip            = p.zip;
  S.packName       = p.packName;
  S.files          = p.files;
  S.originals      = p.originals;
  S.current        = p.current;
  S.currentKind    = p.currentKind;
  S.history        = p.history;
  S.hIdx           = p.hIdx;
  S.layers         = p.layers;
  S.activeLayerIdx = p.activeLayerIdx;

  // Clear search so the previous pack's query doesn't bleed into the new tree
  document.getElementById('search').value = '';

  const hasFiles = S.files.length > 0;
  document.getElementById('btn-export').disabled       = !hasFiles;
  document.getElementById('btn-export-arrow').disabled = !hasFiles;
  if (hasFiles) {
    document.getElementById('sidebar-actions').classList.add('visible');
    renderTree(p.openFolders);
    if (S.current) { openFile(S.current); }
    else           { setMode('hint'); }
  } else {
    document.getElementById('sidebar-actions').classList.remove('visible');
    setMode('load');
    renderTree(p.openFolders);
  }
  renderPackTabs();
}

async function closePackTab(idx) {
  // If closing the active tab, flush its unsaved edits first
  if (idx === activePackIdx) {
    if (S.current && S.currentKind === 'image') {
      await new Promise(res => {
        const fc = layerFlatCanvas();
        fc.toBlob(blob => blob.arrayBuffer().then(ab => {
          S.current.data = new Uint8Array(ab);
          S.current.modified = true;
          res();
        }), 'image/png');
      });
    } else if (S.current && S.currentKind === 'text') {
      S.current.data = new TextEncoder().encode(document.getElementById('text-editor').value);
      S.current.modified = true;
    }
  }
  if (PACKS.length <= 1) {
    // last tab: reset to empty state
    PACKS[0] = emptyPackSlot();
    activePackIdx = 0;
    Object.assign(S, emptyPackSlot());
    document.getElementById('btn-export').disabled       = true;
    document.getElementById('btn-export-arrow').disabled = true;
    document.getElementById('sidebar-actions').classList.remove('visible');
    setMode('load');
    renderTree();
    renderPackTabs();
    return;
  }
  if (idx === activePackIdx) saveCurrentPack();
  PACKS.splice(idx, 1);
  const newIdx = Math.min(idx, PACKS.length - 1);
  activePackIdx = -1; // force switchToPack to load
  switchToPack(newIdx);
}

function renderPackTabs() {
  const container = document.getElementById('pack-tabs');
  // Keep the + button reference, remove old tabs
  const addBtn = document.getElementById('btn-add-tab');
  container.innerHTML = '';
  PACKS.forEach((p, i) => {
    const tab = document.createElement('span');
    tab.className = 'pack-tab' + (i === activePackIdx ? ' active' : '');
    const nm = document.createElement('span');
    nm.className = 'tab-name';
    nm.textContent = p.packName || 'No pack loaded';
    nm.title = p.packName || 'No pack loaded';
    const cls = document.createElement('span');
    cls.className = 'tab-close';
    cls.textContent = '✕';
    cls.title = 'Close tab';
    cls.addEventListener('click', e => { e.stopPropagation(); closePackTab(i); });
    tab.appendChild(nm);
    tab.appendChild(cls);
    tab.addEventListener('click', () => switchToPack(i));
    container.appendChild(tab);
  });
  container.appendChild(addBtn);
  addBtn.style.display = PACKS.length >= MAX_PACKS ? 'none' : '';
}

const MAX_PACKS = 4;

function openNewPackTab() {
  if (PACKS.length >= MAX_PACKS) {
    toast(`Maximum of ${MAX_PACKS} packs can be open at once`, 'e', 3500);
    return;
  }
  // Save current, push blank slot, switch to it, then prompt for file
  saveCurrentPack();
  PACKS.push(emptyPackSlot());
  activePackIdx = PACKS.length - 1;
  Object.assign(S, emptyPackSlot());
  document.getElementById('btn-export').disabled       = true;
  document.getElementById('btn-export-arrow').disabled = true;
  document.getElementById('sidebar-actions').classList.remove('visible');
  setMode('load');
  renderTree();
  renderPackTabs();
  // Trigger file picker
  document.getElementById('add-tab-input').click();
}

function buildTree(files) {
// Build a nested folder structure from flat paths
const root = {__files:[], __folders:{}};
files.forEach(f => {
const parts = f.path.split('/');
let node = root;
for (let i=0; i<parts.length-1; i++) {
const seg = parts[i];
if (!node.__folders[seg]) node.__folders[seg] = {__files:[], __folders:{}};
node = node.__folders[seg];
}
node.__files.push(f);
});
return root;
}

function getOpenFolders() {
const open = new Set();
document.querySelectorAll('.folder-row.open').forEach(row => {
const lbl = row.querySelector('.folder-label');
if (lbl) open.add(lbl.textContent);
});
// Also store by full path via data attribute
document.querySelectorAll('.folder-row.open[data-path]').forEach(row => {
open.add(row.dataset.path);
});
return open;
}

function renderTree(restoredOpenFolders) {
const openFolders = restoredOpenFolders || getOpenFolders();
const tree = document.getElementById('file-tree');
tree.innerHTML = '';
const q = document.getElementById('search').value.toLowerCase();

const filtered = q
? S.files.filter(f => f.path.toLowerCase().includes(q) || f.name.toLowerCase().includes(q))
: S.files;

if (!filtered.length) {
tree.innerHTML = '<div style="padding:16px 12px;font-size:12.6px;color:var(--dim);text-align:center">No files match</div>';
return;
}

const treeData = buildTree(filtered);
renderNode(tree, treeData, '', q !== '', openFolders);
}

function renderNode(container, node, pathPrefix, expanded, openFolders) {
// Render folders first, sorted
Object.keys(node.__folders).sort().forEach(folderName => {
const childNode = node.__folders[folderName];
const fullPath  = pathPrefix ? `${pathPrefix}/${folderName}` : folderName;
const fileCount = countFiles(childNode);

// A folder is open if: search is active, OR it was open before, OR it contains the active file
const wasOpen = expanded
|| (openFolders && (openFolders.has(folderName) || openFolders.has(fullPath)))
|| (S.current && S.current.path.startsWith(fullPath + '/'));

const rowEl = document.createElement('div');
rowEl.className = 'folder-row' + (wasOpen ? ' open' : '');
rowEl.dataset.path = fullPath;
rowEl.innerHTML = `<span class="folder-icon">▶</span><span style="font-size:13.8px;flex-shrink:0">📁</span><span class="folder-label">${esc(folderName)}</span><span style="color:var(--dim);font-size:10.3px;margin-left:auto;flex-shrink:0;padding-right:4px">${fileCount}</span>`;

const childEl = document.createElement('div');
childEl.className = 'folder-children' + (wasOpen ? '' : ' closed');

rowEl.addEventListener('click', () => {
rowEl.classList.toggle('open');
childEl.classList.toggle('closed');
});

container.appendChild(rowEl);
container.appendChild(childEl);
renderNode(childEl, childNode, fullPath, expanded, openFolders);
});

// Then files
node.__files.forEach(f => {
const row = document.createElement('div');
row.className = 'file-row' + (f.modified?' dirty':'') + (S.current===f?' active':'');
row.dataset.path = f.path;

const kind = kindOf(f.path);
const color = colorOf(f.path);

// Delete button — left side, shown on hover
const delBtn = document.createElement('button');
delBtn.className = 'del-file-btn';
delBtn.title = 'Delete file';
delBtn.textContent = '✕';
delBtn.addEventListener('click', async e => {
e.stopPropagation();
await deleteFile(f);
});
row.appendChild(delBtn);

if (kind === 'image') {
const thumb = document.createElement('img');
thumb.className = 'tex-thumb';
const blob = new Blob([f.data], {type:'image/png'});
const turl = URL.createObjectURL(blob);
thumb.src = turl;
thumb.onload = thumb.onerror = () => URL.revokeObjectURL(turl);
row.appendChild(thumb);
} else {
const icon = document.createElement('span');
icon.className = 'file-icon';
icon.style.color = color;
icon.textContent = iconOf(f.path);
row.appendChild(icon);
}

const lbl = document.createElement('span');
lbl.className = 'file-name';
lbl.style.color = S.current===f ? 'var(--green)' : color;
lbl.textContent = f.name;
row.appendChild(lbl);

// Play Sound button for audio files
if (kind === 'audio') {
const playBtn = document.createElement('button');
playBtn.className = 'play-snd-btn';
playBtn.title = 'Play Sound';
playBtn.textContent = '▶';
playBtn.dataset.path = f.path;
playBtn.addEventListener('click', e => {
e.stopPropagation();
quickPlaySound(f, playBtn);
});
row.appendChild(playBtn);
}

row.addEventListener('click', () => openFile(f));
container.appendChild(row);
});
}

function countFiles(node) {
let n = node.__files.length;
Object.values(node.__folders).forEach(c => n += countFiles(c));
return n;
}

function highlightActive() {
document.querySelectorAll('.file-row').forEach(el => {
const isActive = el.dataset.path === S.current?.path;
el.classList.toggle('active', isActive);
const lbl = el.querySelector('.file-name');
if (lbl) lbl.style.color = isActive ? 'var(--green)' : colorOf(el.dataset.path||'');
});
}

/* ── DELETE FILE ──────────────────────────────────────────── */
async function deleteFile(f) {
const ok = await showConfirm(
'Delete File',
`Permanently remove "${f.path}" from the pack? This cannot be undone.`
);
if (!ok) return;

// Remove from ZIP
S.zip.remove(f.path);

// Remove from file list
const idx = S.files.indexOf(f);
if (idx !== -1) S.files.splice(idx, 1);

// If this was the open file, clear the editor
if (S.current === f) {
S.current     = null;
S.currentKind = null;
if (typeof audioStop === 'function') audioStop();
setMode('hint');
}

toast(`Deleted ${f.name}`, 'i');
renderTree();
}

/* ── Image editing ────────────────────────────────────────── */
async function openImage(f) {
setMode('image');
// Reset CS preview and adj overlay when switching files
if (CS && CS.previewActive) { CS.previewActive = false; CS.previewSnapshot = null; }
if (typeof ADJ_ORIG !== 'undefined' && ADJ_ORIG) { document.getElementById('adj-overlay').classList.add('off'); ADJ_ORIG = null; }
try {
const blob = new Blob([f.data], {type:'image/png'});
const bmp  = await createImageBitmap(blob);
MC.width  = bmp.width;
MC.height = bmp.height;

// Initialize layers: one Background layer with the image
_layerIdCtr = 0;
const bgLayer = layerNew('Background');
bgLayer.ctx.drawImage(bmp, 0, 0);
bmp.close();
S.layers = [bgLayer];
S.activeLayerIdx = 0;
layerComposite();

if (!S.originals.has(f.path)) {
S.originals.set(f.path, MCX.getImageData(0,0,MC.width,MC.height));
}
S.history = [layerSnapshot()];
S.hIdx = 0;

applyZoom(fitZoom());
drawGrid();
updateHistoryUI();
extractPalette();
renderLayersPanel();
} catch(e) {
toast('Could not render image: '+e.message,'e',5000);
console.error('[JhunForge] openImage:',e);
setMode('hint');
}
}

/* ── Text editing ─────────────────────────────────────────── */
function openText(f) {
setMode('text');
let text;
try {
text = new TextDecoder('utf-8', {fatal:true}).decode(f.data);
} catch {
try { text = new TextDecoder('latin1').decode(f.data); }
catch { text = '[Could not decode file as text]'; }
}

const ed = document.getElementById('text-editor');
ed.value = text;

const ext = extOf(f.path).toUpperCase();
document.getElementById('txt-title').textContent = f.name;
document.getElementById('txt-badge').textContent = ext;

updateTextStatus();
}

function openBinary(f) {
setMode('hint');
document.getElementById('ov-hint').classList.remove('off');
const hint = document.getElementById('ov-hint').querySelector('p');
hint.innerHTML = `<strong style="color:var(--muted)">${esc(f.name)}</strong><br><span style="font-size:11.5px;color:var(--dim)">Binary file (${fmtSize(f.data.length)})<br>Use "Download File" to save it, or "Upload &amp; Replace" to swap it.</span>`;
}

/* ── AUDIO ENGINE ─────────────────────────────────────────── */

// Quick preview from sidebar — independent of the full editor
let _qpSource = null;  // currently previewing source node
let _qpBtn    = null;  // the button that triggered it

async function quickPlaySound(f, btn) {
// If this button is already playing → stop it
if (_qpBtn === btn && _qpSource) {
try { _qpSource.stop(); } catch(e) {}
_qpSource = null;
btn.textContent = '▶';
btn.classList.remove('playing');
_qpBtn = null;
return;
}

// Stop any other preview that's running
if (_qpSource) {
try { _qpSource.stop(); } catch(e) {}
_qpSource = null;
}
if (_qpBtn) {
_qpBtn.textContent = '▶';
_qpBtn.classList.remove('playing');
_qpBtn = null;
}

btn.textContent = '…';
btn.classList.add('playing');
_qpBtn = btn;

try {
const ac = audCtx();
const ab = f.data.buffer.slice(f.data.byteOffset, f.data.byteOffset + f.data.byteLength);
const buf = await ac.decodeAudioData(ab);

const src = ac.createBufferSource();
src.buffer = buf;
src.connect(ac.destination);
src.start(0);
_qpSource = src;
btn.textContent = '⏹';

src.onended = () => {
if (_qpBtn === btn) {
btn.textContent = '▶';
btn.classList.remove('playing');
_qpSource = null;
_qpBtn    = null;
}
};
} catch(e) {
btn.textContent = '▶';
btn.classList.remove('playing');
_qpSource = null;
_qpBtn    = null;
toast('Could not play: ' + e.message, 'e', 4000);
}
}

function audCtx() {
if (!AUD.ctx) AUD.ctx = new (window.AudioContext || window.webkitAudioContext)();
if (AUD.ctx.state === 'suspended') AUD.ctx.resume();
return AUD.ctx;
}

async function openAudio(f) {
setMode('audio');
AUD.file = f;

document.getElementById('aud-filename').textContent = f.name;
document.getElementById('aud-meta').textContent = 'Decoding…';
document.getElementById('aud-play').textContent = '▶';

// Reset controls
document.getElementById('pitch-slider').value = 0;
document.getElementById('vol-slider').value   = 100;
document.getElementById('rate-slider').value  = 100;
setPitch(0); setVolume(100); setRate(100);

try {
const ac = audCtx();
const ab = f.data.buffer.slice(f.data.byteOffset, f.data.byteOffset + f.data.byteLength);
AUD.buffer = await ac.decodeAudioData(ab);

const dur = AUD.buffer.duration;
const sr  = AUD.buffer.sampleRate;
const ch  = AUD.buffer.numberOfChannels;
document.getElementById('aud-meta').textContent =
`${fmtTime(dur)}  ·  ${sr} Hz  ·  ${ch === 1 ? 'Mono' : 'Stereo'}  ·  ${fmtSize(f.data.length)}`;
document.getElementById('aud-dur').textContent = fmtTime(dur);

drawWaveform(AUD.buffer);
} catch(e) {
document.getElementById('aud-meta').textContent = 'Could not decode audio: ' + e.message;
toast('Could not decode audio: ' + e.message, 'e', 5000);
console.error('[JhunForge] openAudio:', e);
}
}

function fmtTime(s) {
const m   = Math.floor(s / 60);
const sec = (s % 60).toFixed(3).padStart(6, '0');
return `${m}:${sec}`;
}

/* draw waveform onto the canvas */
function drawWaveform(buffer) {
const cv = document.getElementById('waveform-canvas');
const wrap = document.getElementById('waveform-wrap');
cv.width  = wrap.clientWidth  || 600;
cv.height = wrap.clientHeight || 100;
const ctx = cv.getContext('2d');
ctx.clearRect(0, 0, cv.width, cv.height);

const data = buffer.getChannelData(0);
const step = Math.ceil(data.length / cv.width);
const mid  = cv.height / 2;

// background
ctx.fillStyle = '#161b22';
ctx.fillRect(0, 0, cv.width, cv.height);

// center line
ctx.strokeStyle = 'rgba(255,255,255,.05)';
ctx.lineWidth = 1;
ctx.beginPath(); ctx.moveTo(0, mid); ctx.lineTo(cv.width, mid); ctx.stroke();

// waveform gradient
const grad = ctx.createLinearGradient(0, 0, 0, cv.height);
grad.addColorStop(0,   'rgba(188,140,255,.9)');
grad.addColorStop(0.5, 'rgba(63,185,80,.9)');
grad.addColorStop(1,   'rgba(88,166,255,.9)');
ctx.fillStyle = grad;

for (let x = 0; x < cv.width; x++) {
let min = 1, max = -1;
for (let j = 0; j < step; j++) {
const v = data[x * step + j] || 0;
if (v < min) min = v;
if (v > max) max = v;
}
const h = Math.max(1, (max - min) * mid * 0.9);
const y = mid - (max * mid * 0.9);
ctx.fillRect(x, y, 1, h);
}
}

/* playback */
function audioPlay() {
if (!AUD.buffer) return;
const ac = audCtx();

if (AUD.playing) { audioPause(); return; }

AUD.gainNode = ac.createGain();
AUD.gainNode.gain.value = AUD.volume;
AUD.gainNode.connect(ac.destination);

AUD.source = ac.createBufferSource();
AUD.source.buffer = AUD.buffer;
AUD.source.loop   = AUD.looping;
AUD.source.detune.value       = AUD.pitch;
AUD.source.playbackRate.value = AUD.rate;
AUD.source.connect(AUD.gainNode);
AUD.source.start(0, AUD.pausedAt);
AUD.startedAt = ac.currentTime - AUD.pausedAt;
AUD.playing   = true;
document.getElementById('aud-play').textContent = '⏸';
document.getElementById('aud-play').classList.add('is-playing');
tickPlayhead();

AUD.source.onended = () => {
if (AUD.playing && !AUD.looping) {
audioStop();
}
};
}

function audioPause() {
if (!AUD.playing) return;
AUD.pausedAt = audCtx().currentTime - AUD.startedAt;
AUD.source.stop();
AUD.playing = false;
document.getElementById('aud-play').textContent = '▶';
document.getElementById('aud-play').classList.remove('is-playing');
cancelAnimationFrame(AUD.rafId);
}

function audioStop() {
if (AUD.source) { try { AUD.source.stop(); } catch(e) {} }
AUD.playing  = false;
AUD.pausedAt = 0;
document.getElementById('aud-play').textContent = '▶';
document.getElementById('aud-play').classList.remove('is-playing');
document.getElementById('waveform-progress').style.width = '0%';
document.getElementById('aud-cur').textContent = fmtTime(0);
cancelAnimationFrame(AUD.rafId);
}

function audioSeek(ratio) {
const wasPlaying = AUD.playing;
if (AUD.playing) { try { AUD.source.stop(); } catch(e) {} AUD.playing = false; }
AUD.pausedAt = (AUD.buffer?.duration || 0) * Math.max(0, Math.min(1, ratio));
if (wasPlaying) audioPlay();
else {
document.getElementById('waveform-progress').style.width = (ratio*100)+'%';
document.getElementById('aud-cur').textContent = fmtTime(AUD.pausedAt);
}
}

function tickPlayhead() {
if (!AUD.playing) return;
const elapsed = audCtx().currentTime - AUD.startedAt;
const dur = AUD.buffer.duration;
const pos = AUD.looping ? elapsed % dur : Math.min(elapsed, dur);
const pct = (pos / dur) * 100;
document.getElementById('waveform-progress').style.width = pct + '%';
document.getElementById('aud-cur').textContent = fmtTime(pos);
AUD.rafId = requestAnimationFrame(tickPlayhead);
}

/* rebuild source with new settings without restarting if playing */
function audioRebuild() {
if (!AUD.playing || !AUD.buffer) return;
const pos = audCtx().currentTime - AUD.startedAt;
try { AUD.source.stop(); } catch(e) {}
AUD.playing  = false;
AUD.pausedAt = pos % AUD.buffer.duration;
audioPlay();
}

/* pitch helpers */
function setPitch(cents) {
AUD.pitch = Math.max(-2400, Math.min(2400, cents));
document.getElementById('pitch-slider').value = AUD.pitch;
if (AUD.source) AUD.source.detune.value = AUD.pitch;
// bar fill: 0 cents = 50%, −2400 = 0%, +2400 = 100%
const pct = ((AUD.pitch + 2400) / 4800) * 100;
document.getElementById('pitch-bar-fill').style.width = pct + '%';
const semitones = (AUD.pitch / 100).toFixed(1);
document.getElementById('pitch-display').textContent = `${semitones} st`;
document.getElementById('semi-label').textContent    = `${semitones} semitones`;
}

function setVolume(v) {
AUD.volume = v / 100;
document.getElementById('vol-slider').value = v;
const pct = (v / 200) * 100;
document.getElementById('vol-bar-fill').style.width = pct + '%';
document.getElementById('vol-display').textContent = v + '%';
if (AUD.gainNode) AUD.gainNode.gain.value = AUD.volume;
}

function setRate(v) {
AUD.rate = v / 100;
document.getElementById('rate-slider').value = v;
// 10→400 range; map to 0–100% display
const pct = ((v - 10) / 390) * 100;
document.getElementById('rate-bar-fill').style.width = pct + '%';
document.getElementById('rate-display').textContent = AUD.rate.toFixed(2) + '×';
if (AUD.source) AUD.source.playbackRate.value = AUD.rate;
}

/* Waveform click → seek */
document.getElementById('waveform-wrap').addEventListener('click', e => {
const rect = e.currentTarget.getBoundingClientRect();
audioSeek((e.clientX - rect.left) / rect.width);
});

/* Transport */
document.getElementById('aud-play').addEventListener('click', audioPlay);
document.getElementById('aud-stop').addEventListener('click', audioStop);
document.getElementById('aud-back').addEventListener('click', () => audioSeek(Math.max(0, (AUD.pausedAt - 5) / (AUD.buffer?.duration||1))));
document.getElementById('aud-fwd') .addEventListener('click', () => audioSeek(Math.min(1, (AUD.pausedAt + 5) / (AUD.buffer?.duration||1))));
document.getElementById('aud-loop').addEventListener('click', function() {
AUD.looping = !AUD.looping;
this.classList.toggle('on', AUD.looping);
if (AUD.source) AUD.source.loop = AUD.looping;
});

/* Pitch slider */
document.getElementById('pitch-slider').addEventListener('input', function() { setPitch(+this.value); });

/* Semitone step buttons */
document.getElementById('semi-up')      .addEventListener('click', () => setPitch(AUD.pitch + 100));
document.getElementById('semi-down')    .addEventListener('click', () => setPitch(AUD.pitch - 100));
document.getElementById('semi-up-oct')  .addEventListener('click', () => setPitch(AUD.pitch + 1200));
document.getElementById('semi-down-oct').addEventListener('click', () => setPitch(AUD.pitch - 1200));

/* Octave preset pills */
document.querySelectorAll('.oct-pill[data-cents]').forEach(btn => {
btn.addEventListener('click', () => setPitch(+btn.dataset.cents));
});

/* Volume slider */
document.getElementById('vol-slider').addEventListener('input', function() { setVolume(+this.value); });

/* Rate slider */
document.getElementById('rate-slider').addEventListener('input', function() { setRate(+this.value); });

/* Rate preset pills */
document.querySelectorAll('.oct-pill[data-rate]').forEach(btn => {
btn.addEventListener('click', () => setRate(+btn.dataset.rate));
});

/* Reset */
document.getElementById('aud-reset').addEventListener('click', () => {
audioStop();
AUD.looping = false;
document.getElementById('aud-loop').classList.remove('on');
setPitch(0); setVolume(100); setRate(100);
});

/* Export with pitch applied using OfflineAudioContext */
document.getElementById('aud-render-export').addEventListener('click', async () => {
if (!AUD.buffer) return;
const btn = document.getElementById('aud-render-export');
btn.textContent = '⏳ Rendering…';
btn.disabled = true;
try {
const ac  = audCtx();
const dur = AUD.buffer.duration / AUD.rate;
const sr  = AUD.buffer.sampleRate;
const ch  = AUD.buffer.numberOfChannels;
const oac = new OfflineAudioContext(ch, Math.ceil(dur * sr), sr);

const gainNode = oac.createGain();
gainNode.gain.value = AUD.volume;
gainNode.connect(oac.destination);

const src = oac.createBufferSource();
src.buffer             = AUD.buffer;
src.detune.value       = AUD.pitch;
src.playbackRate.value = AUD.rate;
src.connect(gainNode);
src.start(0);

const rendered = await oac.startRendering();

// Encode to WAV
const wav = encodeWAV(rendered);
const blob = new Blob([wav], {type:'audio/wav'});
const ext  = extOf(AUD.file.name);
const name = AUD.file.name.replace(new RegExp('\\.'+ext+'$','i'), '_pitched.wav');
const a = document.createElement('a');
a.href = URL.createObjectURL(blob);
a.download = name;
a.click();
setTimeout(()=>URL.revokeObjectURL(a.href), 5000);
toast('Exported ' + name, 's');
} catch(e) {
toast('Export failed: '+e.message,'e',5000);
console.error(e);
}
btn.textContent = '⬇ Export with Pitch Applied';
btn.disabled = false;
});

/* WAV encoder */
function encodeWAV(buffer) {
const numCh  = buffer.numberOfChannels;
const sr     = buffer.sampleRate;
const numSmp = buffer.length;
const bps    = 2; // 16-bit
const ab     = new ArrayBuffer(44 + numSmp * numCh * bps);
const view   = new DataView(ab);

function str(off, s) { for (let i=0;i<s.length;i++) view.setUint8(off+i, s.charCodeAt(i)); }
function u32(off, v) { view.setUint32(off, v, true); }
function u16(off, v) { view.setUint16(off, v, true); }

str(0,'RIFF'); u32(4, 36 + numSmp*numCh*bps); str(8,'WAVE');
str(12,'fmt '); u32(16,16); u16(20,1); u16(22,numCh);
u32(24,sr); u32(28,sr*numCh*bps); u16(32,numCh*bps); u16(34,16);
str(36,'data'); u32(40, numSmp*numCh*bps);

let off = 44;
for (let i=0; i<numSmp; i++) {
for (let c=0; c<numCh; c++) {
const s = Math.max(-1, Math.min(1, buffer.getChannelData(c)[i]));
view.setInt16(off, s < 0 ? s*0x8000 : s*0x7FFF, true);
off += 2;
}
}
return ab;
}

function updateTextStatus() {
const ed = document.getElementById('text-editor');
const lines = ed.value.split('\n').length;
const chars = ed.value.length;
document.getElementById('ts-lines').textContent = lines+' lines';
document.getElementById('ts-chars').textContent = chars+' chars';
}

document.getElementById('text-editor').addEventListener('input', updateTextStatus);
document.getElementById('text-editor').addEventListener('keydown', e => {
// Tab support
if (e.key === 'Tab') {
e.preventDefault();
const ed = e.target;
const s = ed.selectionStart, en = ed.selectionEnd;
ed.value = ed.value.slice(0,s) + '  ' + ed.value.slice(en);
ed.selectionStart = ed.selectionEnd = s+2;
}
// Ctrl+S to apply
if ((e.ctrlKey||e.metaKey) && e.key==='s') { e.preventDefault(); applyText(); }
});

document.getElementById('text-editor').addEventListener('click', function() {
const lines = this.value.slice(0,this.selectionStart).split('\n');
const ln = lines.length, col = lines[lines.length-1].length+1;
document.getElementById('ts-cur').textContent = `Ln ${ln}, Col ${col}`;
});

/* ── Apply text ───────────────────────────────────────────── */
function applyText() {
if (!S.current || S.currentKind !== 'text') return;
const text = document.getElementById('text-editor').value;
S.current.data = new TextEncoder().encode(text);
S.current.modified = true;
toast(`Saved ${S.current.name}`,'s');
renderTree();
}

/* ── Format JSON ──────────────────────────────────────────── */
function formatJSON() {
const ed = document.getElementById('text-editor');
try {
// Strip comments for parsing (JSONC support)
const stripped = ed.value.replace(/\/\/[^\n]*/g,'').replace(/\/\*[\s\S]*?\*\//g,'');
const parsed = JSON.parse(stripped);
ed.value = JSON.stringify(parsed, null, 2);
updateTextStatus();
toast('Formatted JSON','s');
} catch(e) {
toast('Invalid JSON: '+e.message,'e',4000);
}
}

/* ── File info ────────────────────────────────────────────── */
function updateFileInfo() {
const f = S.current;
if (!f) return;
document.getElementById('i-name').textContent = f.name;
document.getElementById('i-type').textContent = extOf(f.path).toUpperCase();
document.getElementById('i-size').textContent = fmtSize(f.data.length);
document.getElementById('i-path').textContent = f.path;
const dimsRow = document.getElementById('i-dims-row');
if (extOf(f.path) === 'png') {
  const img = new Image();
  const blob = new Blob([f.data], {type:'image/png'});
  const url = URL.createObjectURL(blob);
  img.onload = () => {
    document.getElementById('i-dims').textContent = img.naturalWidth + ' × ' + img.naturalHeight;
    dimsRow.classList.remove('hidden');
    URL.revokeObjectURL(url);
  };
  img.src = url;
} else {
  dimsRow.classList.add('hidden');
  document.getElementById('i-dims').textContent = '—';
}
}

/* ── Download single file ─────────────────────────────────── */
function downloadCurrentFile() {
if (!S.current) return;
const blob = new Blob([S.current.data]);
const a = document.createElement('a');
a.href     = URL.createObjectURL(blob);
a.download = S.current.name;
a.click();
setTimeout(()=>URL.revokeObjectURL(a.href),5000);
}

/* ── Upload & replace any file ────────────────────────────── */
function uploadAndReplace(file) {
if (!S.current) return;
file.arrayBuffer().then(ab => {
S.current.data = new Uint8Array(ab);
S.current.modified = true;
toast(`Replaced ${S.current.name} with ${file.name}`,'s');
renderTree();
// Re-open to refresh view
openFile(S.current);
}).catch(e=>toast('Upload failed: '+e.message,'e'));
}

/* ── ZOOM ─────────────────────────────────────────────────── */
function fitZoom() {
const a = document.getElementById('canvas-area');
const zx = Math.floor((a.clientWidth -80)/Math.max(1,MC.width));
const zy = Math.floor((a.clientHeight-80)/Math.max(1,MC.height));
return Math.max(1,Math.min(32,Math.min(zx,zy)));
}
function applyZoom(z, anchorX, anchorY) {
const ca = document.getElementById('canvas-area');
const oldZoom = S.zoom;
S.zoom=Math.max(1,Math.min(64,z));
const w=MC.width*S.zoom, h=MC.height*S.zoom;
MC.style.width=w+'px'; MC.style.height=h+'px';
GC.style.width=w+'px'; GC.style.height=h+'px';
// Cap grid canvas pixel size to browser's max canvas limit (~16384px).
// Without this cap, large images at high zoom (e.g. 600px × 28zoom = 16800px)
// cause the canvas allocation to fail, turning GC opaque white and obscuring
// the main canvas beneath it.
const MAX_GC_PX = 8192;
GC.width  = Math.min(w, MAX_GC_PX);
GC.height = Math.min(h, MAX_GC_PX);
document.getElementById('zoom-lbl').textContent=S.zoom+'×';
drawGrid();
// If anchor given, adjust scroll so that pixel under cursor stays fixed
if (anchorX !== undefined && anchorY !== undefined && oldZoom !== S.zoom) {
  const scale = S.zoom / oldZoom;
  ca.scrollLeft = (ca.scrollLeft + anchorX) * scale - anchorX;
  ca.scrollTop  = (ca.scrollTop  + anchorY) * scale - anchorY;
}
}

/* ── GRID ─────────────────────────────────────────────────── */
function drawGrid() {
const on = document.getElementById('btn-grid').classList.contains('on');
if (!on||!MC.width){GC.style.display='none';return;}
GC.style.display='block';
GCX.clearRect(0,0,GC.width,GC.height);
GCX.strokeStyle='rgba(255,255,255,.65)';GCX.lineWidth=1;
// GC pixel dims may be capped below MC.width*zoom x MC.height*zoom to stay
// within browser canvas limits, so scale grid coordinates to GC's actual size.
const zx=GC.width/MC.width, zy=GC.height/MC.height;
for(let x=0;x<=MC.width;x++){GCX.beginPath();GCX.moveTo(x*zx,0);GCX.lineTo(x*zx,GC.height);GCX.stroke();}
for(let y=0;y<=MC.height;y++){GCX.beginPath();GCX.moveTo(0,y*zy);GCX.lineTo(GC.width,y*zy);GCX.stroke();}
}

/* ── DRAWING ──────────────────────────────────────────────── */
function getPixel(e) {
const r=MC.getBoundingClientRect();
return {x:Math.max(0,Math.min(MC.width-1,Math.floor((e.clientX-r.left)/S.zoom))),y:Math.max(0,Math.min(MC.height-1,Math.floor((e.clientY-r.top)/S.zoom)))};
}
function doPencil(x,y){const ctx=activeLayerCtx();const{r,g,b,a}=S.color;ctx.fillStyle=`rgba(${r},${g},${b},${a/255})`;ctx.fillRect(x,y,1,1);}
function doEraser(x,y){activeLayerCtx().clearRect(x,y,1,1);}
function doEyedrop(x,y){const p=MCX.getImageData(x,y,1,1).data;setColor(p[0],p[1],p[2],p[3]);}
function doFill(sx,sy){
const ctx=activeLayerCtx();const lc=activeLayer()?.canvas||MC;
const id=ctx.getImageData(0,0,lc.width,lc.height),d=id.data,W=lc.width;
const idx=(x,y)=>(y*W+x)*4,si=idx(sx,sy);
const[tr,tg,tb,ta]=[d[si],d[si+1],d[si+2],d[si+3]];
const{r,g,b,a}=S.color;
if(tr===r&&tg===g&&tb===b&&ta===a)return;
const vis=new Uint8Array(W*lc.height),q=[[sx,sy]];
while(q.length){const[cx,cy]=q.pop();if(cx<0||cx>=W||cy<0||cy>=lc.height||vis[cy*W+cx])continue;const i=idx(cx,cy);if(d[i]!==tr||d[i+1]!==tg||d[i+2]!==tb||d[i+3]!==ta)continue;vis[cy*W+cx]=1;d[i]=r;d[i+1]=g;d[i+2]=b;d[i+3]=a;q.push([cx+1,cy],[cx-1,cy],[cx,cy+1],[cx,cy-1]);}
ctx.putImageData(id,0,0);
layerComposite();
}

let lastPx=null;
function doStroke(e){
if(!S.current||S.currentKind!=='image')return;
if(S.tool==='cursor')return;
const{x,y}=getPixel(e);
document.getElementById('cursor-info').textContent=`${x}, ${y}`;
if(!S.drawing)return;
if(S.tool==='fill'||S.tool==='pick')return;
if(lastPx){const dx=x-lastPx.x,dy=y-lastPx.y,steps=Math.max(Math.abs(dx),Math.abs(dy));for(let s=0;s<=steps;s++){const px=Math.round(lastPx.x+dx*s/steps),py=Math.round(lastPx.y+dy*s/steps);S.tool==='pencil'?doPencil(px,py):doEraser(px,py);}}
else{S.tool==='pencil'?doPencil(x,y):doEraser(x,y);}
lastPx={x,y};
layerComposite();
}

// Pan state
let panStartX = 0, panStartY = 0, panScrollX = 0, panScrollY = 0, panning = false;

MC.addEventListener('mousedown',e=>{
// If Easy Color Swap is sampling, grab color and bail — don't draw
if (CS.sampling) {
e.preventDefault();
e.stopImmediatePropagation();
const {x,y}=getPixel(e);
const p=MCX.getImageData(x,y,1,1).data;
csSetFrom(p[0],p[1],p[2]);
csCancelSampling();
toast(`Sampled rgb(${p[0]}, ${p[1]}, ${p[2]})`,'i',2000);
return;
}
if(!S.current||S.currentKind!=='image')return;
e.preventDefault();
// Pan / cursor tool
if (S.tool === 'cursor') {
  const ca = document.getElementById('canvas-area');
  panning = true;
  panStartX = e.clientX; panStartY = e.clientY;
  panScrollX = ca.scrollLeft; panScrollY = ca.scrollTop;
  ca.classList.add('panning');
  return;
}
S.drawing=true;lastPx=null;
const{x,y}=getPixel(e);
if(S.tool==='fill'){doFill(x,y);pushHistory();}
if(S.tool==='pick'){doEyedrop(x,y);setTool('pencil');}
if(S.tool==='pencil'){doPencil(x,y);layerComposite();}
if(S.tool==='eraser'){doEraser(x,y);layerComposite();}
});
MC.addEventListener('mousemove', e => {
if (panning) {
  const ca = document.getElementById('canvas-area');
  ca.scrollLeft = panScrollX - (e.clientX - panStartX);
  ca.scrollTop  = panScrollY - (e.clientY - panStartY);
  return;
}
doStroke(e);
});
MC.addEventListener('mouseup',()=>{
if (panning) {
  panning = false;
  document.getElementById('canvas-area').classList.remove('panning');
}
if(S.drawing&&(S.tool==='pencil'||S.tool==='eraser'))pushHistory();
S.drawing=false;lastPx=null;
});
window.addEventListener('mouseup',()=>{
if (panning) { panning = false; document.getElementById('canvas-area').classList.remove('panning'); }
S.drawing=false;lastPx=null;
});
MC.addEventListener('mouseleave',()=>{document.getElementById('cursor-info').textContent='';});
MC.addEventListener('contextmenu',e=>{e.preventDefault();if(S.currentKind==='image'){const{x,y}=getPixel(e);doEyedrop(x,y);}});
MC.addEventListener('touchstart',e=>{
  e.preventDefault();
  if (S.tool === 'cursor') {
    const ca = document.getElementById('canvas-area');
    panning = true;
    panStartX = e.touches[0].clientX; panStartY = e.touches[0].clientY;
    panScrollX = ca.scrollLeft; panScrollY = ca.scrollTop;
    return;
  }
  S.drawing=true;lastPx=null;
},{passive:false});
MC.addEventListener('touchmove',e=>{
  e.preventDefault();
  if (panning) {
    const ca = document.getElementById('canvas-area');
    ca.scrollLeft = panScrollX - (e.touches[0].clientX - panStartX);
    ca.scrollTop  = panScrollY - (e.touches[0].clientY - panStartY);
    return;
  }
  doStroke(e.touches[0]);
},{passive:false});
MC.addEventListener('touchend',()=>{
  panning = false;
  if(S.drawing)pushHistory();
  S.drawing=false;lastPx=null;
});

/* ── HISTORY ──────────────────────────────────────────────── */
function layerSnapshot() {
return {
activeIdx: S.activeLayerIdx,
layers: S.layers.map(l => ({
id: l.id, name: l.name, visible: l.visible,
opacity: l.opacity, blendMode: l.blendMode, locked: l.locked,
data: l.ctx.getImageData(0, 0, l.canvas.width, l.canvas.height),
}))
};
}
function restoreSnapshot(snap) {
S.layers = snap.layers.map(s => {
const l = layerNew(s.name, s.data);
l.id = s.id; l.visible = s.visible; l.opacity = s.opacity;
l.blendMode = s.blendMode; l.locked = s.locked;
return l;
});
S.activeLayerIdx = Math.min(snap.activeIdx, S.layers.length - 1);
layerComposite();
renderLayersPanel();
}
function pushHistory(){
if (!S.layers || !S.layers.length) return;
S.history=S.history.slice(0,S.hIdx+1);
S.history.push(layerSnapshot());
if(S.history.length>20)S.history.shift();
S.hIdx=S.history.length-1;
updateHistoryUI();
}
function undo(){if(S.hIdx>0){S.hIdx--;restoreSnapshot(S.history[S.hIdx]);updateHistoryUI();}}
function redo(){if(S.hIdx<S.history.length-1){S.hIdx++;restoreSnapshot(S.history[S.hIdx]);updateHistoryUI();}}
function updateHistoryUI(){const el=document.getElementById('hist-list');el.innerHTML='';S.history.forEach((_,i)=>{const d=document.createElement('div');d.className='hitem'+(i===S.hIdx?' on':'');d.innerHTML=`<span class="hdot"></span>State ${i+1}`;d.onclick=()=>{S.hIdx=i;restoreSnapshot(S.history[i]);updateHistoryUI();};el.appendChild(d);});el.scrollTop=el.scrollHeight;}

/* ── COLOR ────────────────────────────────────────────────── */
function setColor(r,g,b,a=255){S.color={r,g,b,a};document.getElementById('sr').value=r;document.getElementById('vr').textContent=r;document.getElementById('sg').value=g;document.getElementById('vg').textContent=g;document.getElementById('sb').value=b;document.getElementById('vb').textContent=b;document.getElementById('sa').value=a;document.getElementById('va').textContent=a;const hex='#'+[r,g,b].map(v=>v.toString(16).padStart(2,'0')).join('').toUpperCase();document.getElementById('c-hex').value=hex;document.getElementById('c-swatch').style.background=`rgba(${r},${g},${b},${a/255})`;document.getElementById('c-native').value=hex;}
function syncColor(){const{r,g,b,a}=S.color;const hex='#'+[r,g,b].map(v=>v.toString(16).padStart(2,'0')).join('').toUpperCase();document.getElementById('c-hex').value=hex;document.getElementById('c-swatch').style.background=`rgba(${r},${g},${b},${a/255})`;document.getElementById('c-native').value=hex;}
['r','g','b','a'].forEach(ch=>{document.getElementById(`s${ch}`).addEventListener('input',function(){S.color[ch]=+this.value;document.getElementById(`v${ch}`).textContent=this.value;syncColor();});});
document.getElementById('c-hex').addEventListener('change',function(){const h=this.value.replace('#','');if(!/^[0-9a-fA-F]{6}$/.test(h))return;setColor(parseInt(h.slice(0,2),16),parseInt(h.slice(2,4),16),parseInt(h.slice(4,6),16),S.color.a);});
document.getElementById('c-native').addEventListener('input',function(){const h=this.value.replace('#','');setColor(parseInt(h.slice(0,2),16),parseInt(h.slice(2,4),16),parseInt(h.slice(4,6),16),S.color.a);});

/* ── Color Wheel ─────────────────────────────────────────── */
(function(){
  const wCvs = document.getElementById('c-wheel');
  const wCur = document.getElementById('c-wheel-cursor');
  const wCtx = wCvs.getContext('2d');
  const cCtx = wCur.getContext('2d');
  const W = 140, R = W/2;

  function drawWheel() {
    const img = wCtx.createImageData(W, W);
    for (let y = 0; y < W; y++) {
      for (let x = 0; x < W; x++) {
        const dx = x - R, dy = y - R;
        const dist = Math.sqrt(dx*dx + dy*dy);
        if (dist > R) { img.data[(y*W+x)*4+3] = 0; continue; }
        const hue = (Math.atan2(dy, dx) / Math.PI / 2 + 1) % 1;
        const sat = dist / R;
        // HSV to RGB with value=1
        const h6 = hue * 6, i = Math.floor(h6), f = h6 - i;
        const p = 1 - sat, q = 1 - sat*f, t = 1 - sat*(1-f);
        let r,g,b;
        switch(i%6){case 0:r=1;g=t;b=p;break;case 1:r=q;g=1;b=p;break;case 2:r=p;g=1;b=t;break;case 3:r=p;g=q;b=1;break;case 4:r=t;g=p;b=1;break;default:r=1;g=p;b=q;}
        const idx = (y*W+x)*4;
        img.data[idx]=r*255; img.data[idx+1]=g*255; img.data[idx+2]=b*255; img.data[idx+3]=255;
      }
    }
    wCtx.putImageData(img, 0, 0);
  }

  function rgbToHsv(r,g,b){
    r/=255;g/=255;b/=255;
    const max=Math.max(r,g,b),min=Math.min(r,g,b),d=max-min;
    let h=0,s=max===0?0:d/max,v=max;
    if(d){if(max===r)h=(g-b)/d%6;else if(max===g)h=(b-r)/d+2;else h=(r-g)/d+4;h/=6;if(h<0)h+=1;}
    return{h,s,v};
  }

  function drawCursor(h, s) {
    cCtx.clearRect(0,0,W,W);
    const angle = h * Math.PI * 2;
    const cx = R + s * R * Math.cos(angle);
    const cy = R + s * R * Math.sin(angle);
    cCtx.beginPath();
    cCtx.arc(cx, cy, 6, 0, Math.PI*2);
    cCtx.strokeStyle = '#fff';
    cCtx.lineWidth = 2;
    cCtx.stroke();
    cCtx.beginPath();
    cCtx.arc(cx, cy, 5, 0, Math.PI*2);
    cCtx.strokeStyle = '#000';
    cCtx.lineWidth = 1;
    cCtx.stroke();
  }

  function updateWheelCursor() {
    const {h, s} = rgbToHsv(S.color.r, S.color.g, S.color.b);
    drawCursor(h, s);
  }

  function pickFromWheel(e) {
    const rect = wCvs.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (W / rect.width);
    const y = (e.clientY - rect.top)  * (W / rect.height);
    const dx = x - R, dy = y - R;
    const dist = Math.min(Math.sqrt(dx*dx+dy*dy), R);
    const hue = ((Math.atan2(dy, dx) / Math.PI / 2) + 1) % 1;
    const sat = dist / R;
    // HSV(hue, sat, 1) to RGB — preserve value from current color
    const {v} = rgbToHsv(S.color.r, S.color.g, S.color.b);
    const h6=hue*6,i=Math.floor(h6),f=h6-i;
    const p=v*(1-sat),q=v*(1-sat*f),t=v*(1-sat*(1-f));
    let r,g,b;
    switch(i%6){case 0:r=v;g=t;b=p;break;case 1:r=q;g=v;b=p;break;case 2:r=p;g=v;b=t;break;case 3:r=p;g=q;b=v;break;case 4:r=t;g=p;b=v;break;default:r=v;g=p;b=q;}
    setColor(Math.round(r*255), Math.round(g*255), Math.round(b*255), S.color.a);
  }

  drawWheel();
  let dragging = false;
  wCvs.addEventListener('mousedown', e => { dragging=true; pickFromWheel(e); });
  window.addEventListener('mousemove', e => { if(dragging) pickFromWheel(e); });
  window.addEventListener('mouseup', () => { dragging=false; });

  // Patch setColor to also update cursor
  const _origSetColor = setColor;
  setColor = function(r,g,b,a=255){
    _origSetColor(r,g,b,a);
    const {h,s} = rgbToHsv(r,g,b);
    drawCursor(h,s);
  };
  // Init cursor position
  updateWheelCursor();
})();

/* ── PALETTE ──────────────────────────────────────────────── */
function extractPalette(){if(!MC.width)return;const d=MCX.getImageData(0,0,MC.width,MC.height).data,map=new Map();for(let i=0;i<d.length;i+=4){if(d[i+3]<32)continue;const k=`${d[i]},${d[i+1]},${d[i+2]}`;map.set(k,(map.get(k)||0)+1);}const pal=[...map.entries()].sort((a,b)=>b[1]-a[1]).slice(0,32);const grid=document.getElementById('palette');grid.innerHTML='';pal.forEach(([k])=>{const[r,g,b]=k.split(',').map(Number);const c=document.createElement('div');c.className='pcell';c.style.background=`rgb(${r},${g},${b})`;c.title=`rgb(${r},${g},${b})`;c.onclick=()=>{setColor(r,g,b,S.color.a);grid.querySelectorAll('.pcell').forEach(x=>x.classList.remove('on'));c.classList.add('on');};grid.appendChild(c);});}

