function applyImage(){
if(!S.current||S.currentKind!=='image')return;
const fc = layerFlatCanvas();
fc.toBlob(blob=>{blob.arrayBuffer().then(ab=>{S.current.data=new Uint8Array(ab);S.current.modified=true;toast(`Applied changes to ${S.current.name}`,'s');renderTree();});},'image/png');
}

