if(!ok)return;
const orig=S.originals.get(S.current.path);if(!orig){toast('No original saved','i');return;}
_layerIdCtr=0;
S.layers=[layerNew('Background',orig)];
S.activeLayerIdx=0;
MC.width=orig.width;MC.height=orig.height;
layerComposite();
S.history=[layerSnapshot()];S.hIdx=0;
