/* ── EXPORT DROPDOWN LOGIC ── */
const exportDropdown = document.getElementById('export-dropdown');

document.getElementById('btn-export-arrow').addEventListener('click', e => {
e.stopPropagation();
exportDropdown.classList.toggle('open');
});

// Close dropdown when clicking elsewhere
document.addEventListener('click', () => exportDropdown.classList.remove('open'));

// Main button defaults to last used format (stored in S.exportExt, default mcpack)
document.getElementById('btn-export').addEventListener('click', () => {
if (!S.zip) return;
doExport(S.exportExt || 'mcpack');
});

document.getElementById('exp-mcpack').addEventListener('click', () => {
exportDropdown.classList.remove('open');
doExport('mcpack');
});

document.getElementById('exp-zip').addEventListener('click', () => {
exportDropdown.classList.remove('open');
doExport('zip');
});

async function doExport(ext) {
if (!S.zip) return;
S.exportExt = ext;

// flush current image if open — flatten all layers first
if (S.current && S.currentKind === 'image') {
await new Promise(res => {
const fc = layerFlatCanvas();
fc.toBlob(blob => blob.arrayBuffer().then(ab => { S.current.data = new Uint8Array(ab); S.current.modified = true; res(); }), 'image/png');
});
}
// flush current text if open
if (S.current && S.currentKind === 'text') {
S.current.data = new TextEncoder().encode(document.getElementById('text-editor').value);
S.current.modified = true;
}

// Regenerate UUIDs in manifest.json so Minecraft won't detect as duplicate
const manifestFile = S.files.find(f => f.path === 'manifest.json' || f.path.endsWith('/manifest.json'));
if (manifestFile) {
try {
const text = new TextDecoder().decode(manifestFile.data);
const manifest = JSON.parse(text);
// Replace all UUIDs recursively
function freshUUIDs(obj) {
if (Array.isArray(obj)) { obj.forEach(freshUUIDs); return; }
if (obj && typeof obj === 'object') {
for (const key of Object.keys(obj)) {
if (key === 'uuid' && typeof obj[key] === 'string') {
obj[key] = crypto.randomUUID();
} else {
freshUUIDs(obj[key]);
}
}
}
}
freshUUIDs(manifest);
manifestFile.data = new TextEncoder().encode(JSON.stringify(manifest, null, 2));
manifestFile.modified = true;
} catch(e) {
console.warn('[Export] Could not update manifest UUIDs:', e);
}
}

toast(`Building ${ext.toUpperCase()}…`, 'i', 1500);
S.files.forEach(f => { if (f.modified) S.zip.file(f.path, f.data); });
const content = await S.zip.generateAsync({ type: 'blob', compression: 'DEFLATE', compressionOptions: { level: 6 } });
const filename = `${S.packName}_edited.${ext}`;
const a = document.createElement('a'); a.href = URL.createObjectURL(content); a.download = filename; a.click();
setTimeout(() => URL.revokeObjectURL(a.href), 5000);
toast(`Exported ${filename}`, 's');
}

