function setTool(t){
  S.tool=t;
  ['cursor','pencil','eraser','fill','pick'].forEach(x=>document.getElementById(`t-${x}`).classList.toggle('on',x===t));
  const ca = document.getElementById('canvas-area');
  ca.classList.toggle('tool-cursor', t === 'cursor');
}
