document.getElementById('t-pencil').onclick=()=>setTool('pencil');
document.getElementById('t-eraser').onclick=()=>setTool('eraser');
document.getElementById('t-fill')  .onclick=()=>setTool('fill');
document.getElementById('t-pick')  .onclick=()=>setTool('pick');
document.getElementById('btn-zin') .onclick=()=>applyZoom(S.zoom+1);
document.getElementById('btn-zout').onclick=()=>applyZoom(Math.max(1,S.zoom-1));
document.getElementById('btn-fit') .onclick=()=>applyZoom(fitZoom());
