document.getElementById('canvas-area').addEventListener('wheel', e => {
  e.preventDefault();
  const ca = document.getElementById('canvas-area');
  const rect = ca.getBoundingClientRect();
  const mx = e.clientX - rect.left; // mouse offset within scroll container
  const my = e.clientY - rect.top;
  const newZoom = e.deltaY < 0
    ? Math.min(64, S.zoom + 1)
    : Math.max(1, S.zoom - 1);
  if (newZoom !== S.zoom) applyZoom(newZoom, mx, my);
}, { passive: false });

/* ── KEYBOARD ─────────────────────────────────────────────── */
document.addEventListener('keydown',e=>{
if(e.target.tagName==='INPUT'||e.target.tagName==='TEXTAREA')return;
if(e.key==='v'||e.key==='V')setTool('cursor');
if(e.key==='b'||e.key==='B')setTool('pencil');
if(e.key==='e'||e.key==='E')setTool('eraser');
if(e.key==='f'||e.key==='F')setTool('fill');
if(e.key==='i'||e.key==='I')setTool('pick');
if((e.ctrlKey||e.metaKey)&&e.key==='z'&&!e.shiftKey){e.preventDefault();undo();}
if((e.ctrlKey||e.metaKey)&&(e.key==='y'||(e.shiftKey&&e.key==='Z'))){e.preventDefault();redo();}
if(e.key==='+'||e.key==='=')applyZoom(S.zoom+1);
if(e.key==='-')applyZoom(Math.max(1,S.zoom-1));
});

