/* ── PROMPT HELPER ────────────────────────────────────────── */
/* ── FOLDER BROWSER ───────────────────────────────────────── */
function getFolderList() {
  const folders = new Set(['(root)']);
  S.files.forEach(f => {
    const parts = f.path.split('/');
    for (let i = 1; i < parts.length; i++) {
      folders.add(parts.slice(0, i).join('/'));
    }
  });
  return [...folders].sort();
}

function showFolderBrowser() {
  return new Promise(resolve => {
    const list = document.getElementById('fb-list');
    const selLabel = document.getElementById('fb-selected');
    const bg = document.getElementById('fb-bg');
    let chosen = '';

    // Build list
    list.innerHTML = '';
    getFolderList().forEach(folder => {
      const item = document.createElement('div');
      item.className = 'fb-item';
      const depth = folder === '(root)' ? 0 : folder.split('/').length;
      item.style.paddingLeft = (10 + depth * 12) + 'px';
      const icon = document.createElement('span');
      icon.className = 'fb-icon';
      icon.textContent = '📁';
      const lbl = document.createElement('span');
      lbl.textContent = folder === '(root)' ? '/ (pack root)' : folder;
      item.appendChild(icon);
      item.appendChild(lbl);
      item.addEventListener('click', () => {
        list.querySelectorAll('.fb-item').forEach(i => i.classList.remove('selected'));
        item.classList.add('selected');
        chosen = folder === '(root)' ? '' : folder;
        selLabel.textContent = chosen ? chosen : '/ (pack root)';
      });
      list.appendChild(item);
    });

    selLabel.textContent = 'No folder selected (will use pack root)';
    chosen = '';
    bg.classList.remove('off');

    const close = val => {
      bg.classList.add('off');
      document.getElementById('fb-ok').onclick = null;
      document.getElementById('fb-cancel').onclick = null;
      resolve(val);
    };

    document.getElementById('fb-ok').onclick     = () => close(chosen);
    document.getElementById('fb-cancel').onclick = () => close(null);
    bg.onclick = e => { if (e.target === bg) close(null); };
  });
}

function showPrompt(title, desc, placeholder, validate) {
return new Promise(resolve => {
document.getElementById('prompt-title').textContent  = title;
document.getElementById('prompt-desc').textContent   = desc;
const input = document.getElementById('prompt-input');
input.value       = '';
input.placeholder = placeholder;
document.getElementById('prompt-bg').classList.remove('off');
input.focus();

const close = val => {
document.getElementById('prompt-bg').classList.add('off');
input.onkeydown = null;
document.getElementById('prompt-ok').onclick     = null;
document.getElementById('prompt-cancel').onclick = null;
resolve(val);
};

const submit = () => {
const val = input.value.trim();
if (!val) { input.focus(); return; }
if (validate) {
const err = validate(val);
if (err) { toast(err, 'e'); input.focus(); return; }
}
close(val);
};

document.getElementById('prompt-ok')    .onclick = submit;
document.getElementById('prompt-cancel').onclick = () => close(null);
input.onkeydown = e => {
if (e.key === 'Enter')  { e.preventDefault(); submit(); }
if (e.key === 'Escape') { e.preventDefault(); close(null); }
};
});
}

/* ── FOLDER OR TYPE PICKER ───────────────────────────────── */
// Shows a combined modal: folder tree on the left + manual text input.
// Resolves with the chosen/typed path string, or null if cancelled.
function showFolderOrTypePicker(title, desc) {
  return new Promise(resolve => {
    const bg = document.createElement('div');
    bg.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.65);display:flex;align-items:center;justify-content:center;z-index:10001;backdrop-filter:blur(3px)';

    const box = document.createElement('div');
    box.style.cssText = 'background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:22px;width:420px;display:flex;flex-direction:column;gap:12px;box-shadow:0 20px 60px rgba(0,0,0,.5);max-height:90vh;overflow:hidden';

    const h3 = document.createElement('h3');
    h3.textContent = title;
    h3.style.cssText = 'font-family:var(--pixel);font-size:9.2px;color:var(--text);flex-shrink:0';

    const p = document.createElement('p');
    p.textContent = desc;
    p.style.cssText = 'font-size:12.6px;color:var(--muted);line-height:1.5;flex-shrink:0';

    // Folder list
    const listLabel = document.createElement('div');
    listLabel.textContent = 'Browse folders:';
    listLabel.style.cssText = 'font-size:11.5px;color:var(--muted);flex-shrink:0';

    const list = document.createElement('div');
    list.style.cssText = 'overflow-y:auto;border:1px solid var(--border);border-radius:4px;background:var(--bg);min-height:120px;max-height:200px;flex-shrink:0';
    list.style.cssText += ';scrollbar-width:thin';

    let chosen = '';
    getFolderList().forEach(folder => {
      const item = document.createElement('div');
      const depth = folder === '(root)' ? 0 : folder.split('/').length;
      item.style.cssText = `padding:5px 10px 5px ${10 + depth * 12}px;font-size:12.6px;color:var(--muted);cursor:pointer;display:flex;align-items:center;gap:6px;border-left:2px solid transparent;transition:all .1s`;
      const icon = document.createElement('span');
      icon.textContent = '📁';
      icon.style.fontSize = '13px';
      const lbl = document.createElement('span');
      lbl.textContent = folder === '(root)' ? '/ (pack root)' : folder;
      item.appendChild(icon);
      item.appendChild(lbl);
      item.addEventListener('click', () => {
        list.querySelectorAll('[data-fb]').forEach(i => {
          i.style.color = 'var(--muted)';
          i.style.background = '';
          i.style.borderLeftColor = 'transparent';
        });
        item.style.color = 'var(--green)';
        item.style.background = 'rgba(63,185,80,.07)';
        item.style.borderLeftColor = 'var(--green)';
        chosen = folder === '(root)' ? '' : folder;
        input.value = chosen;
      });
      item.dataset.fb = '1';
      list.appendChild(item);
    });

    // Manual input
    const inputLabel = document.createElement('div');
    inputLabel.textContent = 'Or type a folder path:';
    inputLabel.style.cssText = 'font-size:11.5px;color:var(--muted);flex-shrink:0';

    const input = document.createElement('input');
    input.type = 'text';
    input.placeholder = 'e.g. textures/blocks  (leave blank for root)';
    input.spellcheck = false;
    input.style.cssText = 'width:100%;background:var(--bg);border:1px solid var(--border);border-radius:4px;color:var(--text);font-family:var(--mono);font-size:13.8px;padding:8px 10px;outline:none;flex-shrink:0';
    input.addEventListener('focus', () => input.style.borderColor = 'var(--blue)');
    input.addEventListener('blur',  () => input.style.borderColor = 'var(--border)');

    // Buttons
    const acts = document.createElement('div');
    acts.style.cssText = 'display:flex;justify-content:flex-end;gap:8px;flex-shrink:0';

    const btnCancel = document.createElement('button');
    btnCancel.className = 'btn-s';
    btnCancel.textContent = 'Cancel';

    const btnOk = document.createElement('button');
    btnOk.className = 'btn-p';
    btnOk.textContent = 'Select';

    acts.appendChild(btnCancel);
    acts.appendChild(btnOk);

    box.appendChild(h3);
    box.appendChild(p);
    box.appendChild(listLabel);
    box.appendChild(list);
    box.appendChild(inputLabel);
    box.appendChild(input);
    box.appendChild(acts);
    bg.appendChild(box);
    document.body.appendChild(bg);

    const close = val => {
      document.body.removeChild(bg);
      resolve(val);
    };

    btnOk.onclick = () => close(input.value.trim().replace(/^\/+|\/+$/g, ''));
    btnCancel.onclick = () => close(null);
    bg.addEventListener('click', e => { if (e.target === bg) close(null); });
    input.addEventListener('keydown', e => {
      if (e.key === 'Enter')  { e.preventDefault(); btnOk.click(); }
      if (e.key === 'Escape') { e.preventDefault(); close(null); }
    });

    setTimeout(() => input.focus(), 50);
  });
}

/* ── ADD FILES ────────────────────────────────────────────── */
document.getElementById('add-files-input').addEventListener('change', async e => {
const files = [...e.target.files];
if (!files.length) return;
e.target.value = '';

// Ask where to place them — type or browse
let dest;
const browseChoice = await showFolderOrTypePicker(
  'Add Files',
  `Adding ${files.length} file(s). Choose a destination folder inside the pack:`
);
if (browseChoice === null) return; // cancelled
dest = browseChoice;

const prefix = dest.trim().replace(/^\/+|\/+$/g,''); // strip slashes

for (const file of files) {
const path = prefix ? `${prefix}/${file.name}` : file.name;
const data = new Uint8Array(await file.arrayBuffer());
// Check for duplicate
const existing = S.files.find(f => f.path === path);
if (existing) {
existing.data     = data;
existing.modified = true;
toast(`Updated: ${path}`, 'i');
} else {
S.files.push({ name: file.name, path, data, modified: true, type: kindOf(path) });
S.zip.file(path, data);
toast(`Added: ${path}`, 's');
}
}
S.files.sort((a,b) => a.path.localeCompare(b.path));
renderTree();
});

document.getElementById('btn-add-files').addEventListener('click', () => {
if (!S.zip) return;
document.getElementById('add-files-input').click();
});

/* ── CREATE NEW FOLDER ────────────────────────────────────── */
document.getElementById('btn-new-folder').addEventListener('click', async () => {
if (!S.zip) return;

const name = await showPrompt(
'Create New Folder',
'Enter the full folder path to create inside the pack:',
'e.g. textures/custom/blocks',
val => {
if (/[<>:"|?*\\]/.test(val)) return 'Folder name contains invalid characters.';
return null;
}
);
if (!name) return;

const cleanPath = name.replace(/^\/+|\/+$/g,'');

// Folders are virtual in ZIPs — we add a placeholder .gitkeep so it shows up
const placeholderPath = `${cleanPath}/.gitkeep`;
const placeholderData = new TextEncoder().encode('');
S.files.push({ name: '.gitkeep', path: placeholderPath, data: placeholderData, modified: true, type: 'text' });
S.zip.file(placeholderPath, placeholderData);
S.files.sort((a,b) => a.path.localeCompare(b.path));
renderTree();
toast(`Created folder: ${cleanPath}`, 's');
});

/* ── CREATE NEW TEXTURE ───────────────────────────────────── */
/* ── TEMPLATE ZIP (base64-embedded Bedrock textures) ─────── */
const TEMPLATES_B64 = '';

let templateZip = null;
let templateList = [];  // [{path, name, cat}]
let tmplSelectedPath = null;
let tmplCat = 'blocks';
let pendingTexturePath = null; // the namePng chosen before the picker opened

async function loadTemplateZip() {
if (templateZip) return;
const binary = atob(TEMPLATES_B64);
const bytes = new Uint8Array(binary.length);
for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
templateZip = await JSZip.loadAsync(bytes);
templateList = [];
templateZip.forEach((p, entry) => {
if (entry.dir) return;
const low = p.toLowerCase();
if (!low.endsWith('.png')) return;
const name = p.split('/').pop().replace(/\.png$/i,'');
let cat = 'other';
if (/\/blocks\//.test(low)) cat = 'blocks';
else if (/\/items\//.test(low)) cat = 'items';
templateList.push({ path: p, name, cat });
});
templateList.sort((a,b) => a.name.localeCompare(b.name));
}

/* open the two-option picker after path is chosen */
function openTexOptionPicker(namePng) {
pendingTexturePath = namePng;
document.getElementById('tex-option-path-label').textContent =
`Creating: ${namePng} — choose how to fill it:`;
document.getElementById('tex-option-bg').classList.remove('off');
}

document.getElementById('btn-new-texture').addEventListener('click', async () => {
if (!S.zip) return;

// Step 1: browse or type a folder
const folderPath = await showFolderOrTypePicker(
  'Create New Texture',
  'Choose a folder to place the new texture in:'
);
if (folderPath === null) return;

// Step 2: ask just for the file name
const fileName = await showPrompt(
  'Create New Texture',
  'Enter the texture name (.png added automatically):',
  'e.g. my_sword',
  val => {
    if (!val.trim()) return 'Name cannot be empty.';
    if (/[<>:"|?*\\/]/.test(val)) return 'Name contains invalid characters.';
    return null;
  }
);
if (!fileName) return;

const prefix = folderPath.trim().replace(/^\/+|\/+$/g, '');
const rawName = prefix ? `${prefix}/${fileName.trim()}` : fileName.trim();
const namePng = rawName.replace(/\.png$/i,'') + '.png';
if (S.files.find(f => f.path === namePng)) {
toast(`File already exists: ${namePng}`, 'e'); return;
}
openTexOptionPicker(namePng);
});

/* ── Size picker for blank canvas ─────────────────────────── */
function showSizePicker() {
  return new Promise(resolve => {
    const sizes = [16, 32, 64, 128];
    const bg = document.createElement('div');
    bg.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:20000;display:flex;align-items:center;justify-content:center;';
    const box = document.createElement('div');
    box.style.cssText = 'background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:24px 28px;display:flex;flex-direction:column;gap:16px;min-width:260px;';
    const title = document.createElement('div');
    title.textContent = 'Canvas Size';
    title.style.cssText = 'font-family:var(--mono);font-weight:700;font-size:13.8px;color:var(--text);';
    const sub = document.createElement('div');
    sub.textContent = 'Choose a starting canvas size:';
    sub.style.cssText = 'font-size:12.6px;color:var(--muted);';
    const grid = document.createElement('div');
    grid.style.cssText = 'display:grid;grid-template-columns:1fr 1fr;gap:8px;';
    sizes.forEach(s => {
      const btn = document.createElement('button');
      btn.textContent = `${s} × ${s}`;
      btn.style.cssText = 'font-family:var(--mono);font-size:12.6px;font-weight:600;padding:10px;border-radius:6px;border:1px solid var(--border);background:var(--surface2);color:var(--text);cursor:pointer;transition:all .15s;';
      btn.onmouseenter = () => { btn.style.borderColor = 'var(--green)'; btn.style.color = 'var(--green)'; };
      btn.onmouseleave = () => { btn.style.borderColor = 'var(--border)'; btn.style.color = 'var(--text)'; };
      btn.onclick = () => { document.body.removeChild(bg); resolve(s); };
      grid.appendChild(btn);
    });
    const cancel = document.createElement('button');
    cancel.textContent = 'Cancel';
    cancel.style.cssText = 'font-family:var(--mono);font-size:11.5px;padding:7px;border-radius:6px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;';
    cancel.onclick = () => { document.body.removeChild(bg); resolve(null); };
    box.appendChild(title); box.appendChild(sub); box.appendChild(grid); box.appendChild(cancel);
    bg.appendChild(box);
    bg.onclick = e => { if (e.target === bg) { document.body.removeChild(bg); resolve(null); } };
    document.body.appendChild(bg);
  });
}

/* ── Option: Create Blank ──────────────────────────────────── */
document.getElementById('toc-blank').addEventListener('click', async () => {
document.getElementById('tex-option-bg').classList.add('off');
const size = await showSizePicker();
if (!size) return;
const namePng  = pendingTexturePath;
const fileName = namePng.split('/').pop();
const tmpCvs   = document.createElement('canvas');
tmpCvs.width = tmpCvs.height = size;
const pngBlob = await new Promise(r => tmpCvs.toBlob(r, 'image/png'));
const pngData = new Uint8Array(await pngBlob.arrayBuffer());
const fileObj = { name: fileName, path: namePng, data: pngData, modified: true, type: 'image' };
S.files.push(fileObj);
S.zip.file(namePng, pngData);
S.files.sort((a,b) => a.path.localeCompare(b.path));
renderTree();
toast(`Created blank ${namePng}`, 's');
await openFile(fileObj);
});

