/* Render template grid */
async function renderTmplGrid() {
const grid  = document.getElementById('tmpl-grid');
const q     = document.getElementById('tmpl-search').value.toLowerCase();
const items = templateList.filter(t => {
if (tmplCat !== 'all' && t.cat !== tmplCat) return false;
if (q && !t.name.toLowerCase().includes(q)) return false;
return true;
});

grid.innerHTML = '';

// Sword Templates – loaded from icons/ folder
if (tmplCat === 'sword-templates') {
  const swordTemplates = [
    { name: 'Misty v2 (16x)',   dataUri: 'data:image/png;base64,' },
    { name: 'Tightfault (16x)', dataUri: 'data:image/png;base64,' },
  ];
  swordTemplates.forEach(t => {
    const cell = document.createElement('div');
    cell.className = 'tmpl-cell' + (t.name === tmplSelectedPath ? ' selected' : '');
    cell.dataset.path = t.name;
    cell.dataset.sword = '1';

    const img = document.createElement('img');
    img.className = 'tmpl-thumb';
    img.src = t.dataUri;
    img.alt = t.name;
    img.style.imageRendering = 'pixelated';

    const lbl = document.createElement('div');
    lbl.className = 'tmpl-name';
    lbl.textContent = t.name;

    cell.appendChild(img);
    cell.appendChild(lbl);
    cell.dataset.datauri = t.dataUri;
    cell.addEventListener('click', () => {
      tmplSelectedPath = t.name;
      document.querySelectorAll('.tmpl-cell').forEach(c => c.classList.toggle('selected', c.dataset.path === t.name));
      document.getElementById('tmpl-selected-name').textContent = t.name;
      document.getElementById('tmpl-confirm').disabled = false;
    });
    grid.appendChild(cell);
  });
  return;
}

for (const item of items) {
const cell = document.createElement('div');
cell.className = 'tmpl-cell' + (item.path === tmplSelectedPath ? ' selected' : '');
cell.dataset.path = item.path;

const img = document.createElement('img');
img.className = 'tmpl-thumb';
img.alt = item.name;
// lazy-load blob URL on first render
const entry = templateZip.file(item.path);
if (entry) {
entry.async('blob').then(blob => {
const url = URL.createObjectURL(blob);
img.src = url;
img.onload = img.onerror = () => URL.revokeObjectURL(url);
});
}

const lbl = document.createElement('div');
lbl.className   = 'tmpl-name';
lbl.textContent = item.name;

cell.appendChild(img);
cell.appendChild(lbl);
cell.addEventListener('click', () => {
tmplSelectedPath = item.path;
document.querySelectorAll('.tmpl-cell').forEach(c => c.classList.toggle('selected', c.dataset.path === item.path));
document.getElementById('tmpl-selected-name').textContent = item.path;
document.getElementById('tmpl-confirm').disabled = false;
});
grid.appendChild(cell);
}

if (!items.length) {
grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:30px;color:var(--dim);font-size:13.8px">No textures match</div>';
}
}

/* Confirm template selection */
document.getElementById('tmpl-confirm').addEventListener('click', async () => {
if (!tmplSelectedPath) return;
document.getElementById('tmpl-bg').classList.add('off');

const namePng  = pendingTexturePath;
const fileName = namePng.split('/').pop();

// Sword templates are embedded as base64 data URIs
const selectedCell = document.querySelector(`.tmpl-cell[data-path="${CSS.escape(tmplSelectedPath)}"]`);
if (selectedCell && selectedCell.dataset.sword === '1') {
  try {
    const dataUri = selectedCell.dataset.datauri;
    const base64 = dataUri.split(',')[1];
    const binary = atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    const fileObj = { name: fileName, path: namePng, data: bytes, modified: true, type: 'image' };
    S.files.push(fileObj);
    S.zip.file(namePng, bytes);
    S.files.sort((a,b) => a.path.localeCompare(b.path));
    renderTree();
    toast(`Created ${namePng} from template`, 's');
    await openFile(fileObj);
  } catch(e) {
    toast('Could not load sword template', 'e');
  }
  return;
}

const entry = templateZip.file(tmplSelectedPath);
if (!entry) { toast('Template not found', 'e'); return; }

const pngData = new Uint8Array(await entry.async('arraybuffer'));
const fileObj = { name: fileName, path: namePng, data: pngData, modified: true, type: 'image' };
S.files.push(fileObj);
S.zip.file(namePng, pngData);
S.files.sort((a,b) => a.path.localeCompare(b.path));
renderTree();
toast(`Created ${namePng} from template`, 's');
await openFile(fileObj);
});

