// ── Color extraction from image ────────────────────────────
document.getElementById('btn-bg-theme').addEventListener('click', () => {
if (!custState.bgImage) return;
const img = new Image();
img.onload = () => {
const palette = extractImagePalette(img);
applyPaletteAsTheme(palette);
};
img.src = custState.bgImage;
});

function extractImagePalette(img) {
// Downsample to 80×80 for speed
const SIZE  = 80;
const oc    = document.createElement('canvas');
oc.width = oc.height = SIZE;
const ox = oc.getContext('2d', { willReadFrequently: true });
ox.drawImage(img, 0, 0, SIZE, SIZE);
const pixels = ox.getImageData(0, 0, SIZE, SIZE).data;

// Collect opaque pixels as [r,g,b]
const samples = [];
for (let i = 0; i < pixels.length; i += 4) {
if (pixels[i+3] < 128) continue;
samples.push([pixels[i], pixels[i+1], pixels[i+2]]);
}

// Simple k-means with k=6
const k = 6;
let centers = [];
for (let i = 0; i < k; i++) centers.push(samples[Math.floor(i * samples.length / k)]);

for (let iter = 0; iter < 12; iter++) {
const sums   = centers.map(() => [0,0,0,0]); // r,g,b,count
samples.forEach(([r,g,b]) => {
let best = 0, bestD = Infinity;
centers.forEach(([cr,cg,cb], ci) => {
const d = (r-cr)**2+(g-cg)**2+(b-cb)**2;
if (d < bestD) { bestD = d; best = ci; }
});
sums[best][0]+=r; sums[best][1]+=g; sums[best][2]+=b; sums[best][3]++;
});
centers = sums.map(([r,g,b,n],i) =>
n > 0 ? [r/n, g/n, b/n] : centers[i]);
}

return centers.map(([r,g,b]) => ({
r: Math.round(r), g: Math.round(g), b: Math.round(b),
lum: 0.299*r + 0.587*g + 0.114*b,
sat: (() => {
const rn=r/255,gn=g/255,bn=b/255;
const mx=Math.max(rn,gn,bn),mn=Math.min(rn,gn,bn);
const l=(mx+mn)/2;
return l===0||l===1?0:(mx-mn)/(1-Math.abs(2*l-1));
})()
}));
}

function rgbToHex(r,g,b) {
return '#'+[r,g,b].map(v=>Math.round(Math.max(0,Math.min(255,v))).toString(16).padStart(2,'0')).join('');
}

function shiftLuminance(hex, delta) {
const r=parseInt(hex.slice(1,3),16), g=parseInt(hex.slice(3,5),16), b=parseInt(hex.slice(5,7),16);
return rgbToHex(r+delta, g+delta, b+delta);
}

function applyPaletteAsTheme(palette) {
// Sort by luminance
const byLum  = [...palette].sort((a,b) => a.lum - b.lum);
const bySat  = [...palette].sort((a,b) => b.sat - a.sat);

// bg = darkest cluster but clamped so it's not blinding
const bgC    = byLum[0];
// Darken it a bit for true bg
const bgHex  = rgbToHex(Math.round(bgC.r*0.6), Math.round(bgC.g*0.6), Math.round(bgC.b*0.6));
const sfHex  = rgbToHex(Math.round(bgC.r*0.8), Math.round(bgC.g*0.8), Math.round(bgC.b*0.8));
const sf2Hex = rgbToHex(Math.round(bgC.r*0.95), Math.round(bgC.g*0.95), Math.round(bgC.b*0.95));

// Border: slightly lighter than surface
const brdHex = shiftLuminance(sfHex, 20);

// Accent = most saturated color that isn't too dark
const accentC = bySat.find(c => c.lum > 60) || bySat[0];
const accentHex = rgbToHex(accentC.r, accentC.g, accentC.b);
const accentDim = rgbToHex(Math.round(accentC.r*0.55), Math.round(accentC.g*0.55), Math.round(accentC.b*0.55));

// Text: determine from bg luminance
const bgLum = bgC.lum * 0.6;
const textHex   = bgLum < 100 ? '#e6edf3' : '#1f2328';
const mutedHex  = bgLum < 100 ? '#8b949e' : '#57606a';

// Apply
Object.assign(custState, {
'--bg':       bgHex,
'--surface':  sfHex,
'--surface2': sf2Hex,
'--border':   brdHex,
'--text':     textHex,
'--muted':    mutedHex,
'--green':    accentHex,
'--green-dim':accentDim,
});

applyCustState();
syncCustControls();

// Show color preview swatches
document.getElementById('bts-bg').style.background      = bgHex;
document.getElementById('bts-surface').style.background = sfHex;
document.getElementById('bts-accent').style.background  = accentHex;
document.getElementById('bts-text').style.background    = textHex;
const tp = document.getElementById('bg-theme-preview');
tp.style.display = 'flex';
tp.style.marginTop = '20px'; // room for swatch labels

toast('🎨 Theme generated from image!', 's', 3000);
}

/* ── EASY COLOR SWAP ─────────────────────────────────────── */

const CS = {
fromR: 255, fromG: 0,   fromB: 0,
toR:   0,   toG:   255, toB:   0,
tolerance: 0,
sampling: false,
previewActive: false,
previewSnapshot: null,
};

// Open modal
document.getElementById('btn-colorswap').addEventListener('click', () => {
if (!S.current || S.currentKind !== 'image') { toast('Open an image first', 'i', 2000); return; }
CS.previewActive   = false;
CS.previewSnapshot = null;
csUpdateCount();
document.getElementById('colorswap-bg').classList.remove('off');
});

// Close / cancel
function csClose() {
// restore preview if active
if (CS.previewActive && CS.previewSnapshot) {
const al = activeLayer();
if (al) { al.ctx.putImageData(CS.previewSnapshot, 0, 0); layerComposite(); }
CS.previewActive = false;
}
csCancelSampling();
document.getElementById('colorswap-bg').classList.add('off');
}
document.getElementById('colorswap-close').addEventListener('click', csClose);
document.getElementById('colorswap-cancel').addEventListener('click', csClose);

// ── Color sync helpers ────────────────────────────────────
function csSetFrom(r, g, b) {
CS.fromR = r; CS.fromG = g; CS.fromB = b;
const hex = '#' + [r,g,b].map(v => v.toString(16).padStart(2,'0')).join('').toUpperCase();
document.getElementById('cs-from-swatch').style.background = `rgb(${r},${g},${b})`;
document.getElementById('cs-from-native').value = hex;
document.getElementById('cs-from-hex').value    = hex;
if (CS.previewActive) { csUndoPreview(); csRunPreview(); }
csUpdateCount();
}
function csSetTo(r, g, b) {
CS.toR = r; CS.toG = g; CS.toB = b;
const hex = '#' + [r,g,b].map(v => v.toString(16).padStart(2,'0')).join('').toUpperCase();
document.getElementById('cs-to-swatch').style.background = `rgb(${r},${g},${b})`;
document.getElementById('cs-to-native').value = hex;
document.getElementById('cs-to-hex').value    = hex;
if (CS.previewActive) { csUndoPreview(); csRunPreview(); }
csUpdateCount();
}

function csHexToRgb(hex) {
const h = hex.replace('#','');
if (!/^[0-9a-fA-F]{6}$/.test(h)) return null;
return { r: parseInt(h.slice(0,2),16), g: parseInt(h.slice(2,4),16), b: parseInt(h.slice(4,6),16) };
}

// From color pickers
document.getElementById('cs-from-native').addEventListener('input', function() {
const c = csHexToRgb(this.value); if (c) csSetFrom(c.r, c.g, c.b);
});
document.getElementById('cs-from-hex').addEventListener('change', function() {
const c = csHexToRgb(this.value); if (c) csSetFrom(c.r, c.g, c.b);
});

// To color pickers
document.getElementById('cs-to-native').addEventListener('input', function() {
const c = csHexToRgb(this.value); if (c) csSetTo(c.r, c.g, c.b);
});
document.getElementById('cs-to-hex').addEventListener('change', function() {
const c = csHexToRgb(this.value); if (c) csSetTo(c.r, c.g, c.b);
});

// Tolerance slider
document.getElementById('cs-tolerance').addEventListener('input', function() {
CS.tolerance = +this.value;
document.getElementById('cs-tol-val').textContent = this.value;
const hint = CS.tolerance === 0 ? '— exact match only' : `— ±${CS.tolerance} per channel`;
document.getElementById('cs-tol-hint').textContent = hint;
if (CS.previewActive) { csUndoPreview(); csRunPreview(); }
csUpdateCount();
});

// ── Eyedropper / sampling ─────────────────────────────────
document.getElementById('cs-from-eyedrop').addEventListener('click', () => {
if (CS.sampling) { csCancelSampling(); return; }
CS.sampling = true;
document.getElementById('cs-from-eyedrop').classList.add('sampling');
document.getElementById('cs-eyedrop-hint').classList.add('on');
MC.style.cursor = 'cell';
// Temporarily fade the modal so user can see the canvas clearly
document.getElementById('colorswap-bg').style.pointerEvents = 'none';
document.getElementById('colorswap-bg').style.opacity = '0.3';
});

function csCancelSampling() {
CS.sampling = false;
document.getElementById('cs-from-eyedrop').classList.remove('sampling');
document.getElementById('cs-eyedrop-hint').classList.remove('on');
MC.style.cursor = 'crosshair';
document.getElementById('colorswap-bg').style.pointerEvents = '';
document.getElementById('colorswap-bg').style.opacity = '';
}

// Intercept canvas click during sampling

// ── Match counting ────────────────────────────────────────
function csCountMatches() {
const al = activeLayer(); if (!al) return 0;
const id = al.ctx.getImageData(0, 0, al.canvas.width, al.canvas.height).data;
let count = 0;
const t = CS.tolerance;
for (let i = 0; i < id.length; i += 4) {
if (id[i+3] < 1) continue;
if (Math.abs(id[i]   - CS.fromR) <= t &&
Math.abs(id[i+1] - CS.fromG) <= t &&
Math.abs(id[i+2] - CS.fromB) <= t) count++;
}
return count;
}

function csUpdateCount() {
const n = csCountMatches();
document.getElementById('cs-preview-count').textContent = n.toLocaleString();
document.getElementById('colorswap-apply').disabled = n === 0;
}

// ── Preview ───────────────────────────────────────────────
function csUndoPreview() {
const al = activeLayer(); if (!al) return;
if (CS.previewSnapshot) { al.ctx.putImageData(CS.previewSnapshot, 0, 0); layerComposite(); }
CS.previewActive = false;
}

function csRunPreview() {
const al = activeLayer(); if (!al) return;
CS.previewSnapshot = al.ctx.getImageData(0, 0, al.canvas.width, al.canvas.height);
const id = new ImageData(new Uint8ClampedArray(CS.previewSnapshot.data), al.canvas.width, al.canvas.height);
csApplySwap(id.data);
al.ctx.putImageData(id, 0, 0);
layerComposite();
CS.previewActive = true;
}

document.getElementById('cs-preview-btn').addEventListener('click', () => {
if (!S.current || S.currentKind !== 'image') return;
if (CS.previewActive) {
csUndoPreview();
document.getElementById('cs-preview-btn').textContent = '👁 Preview';
} else {
csRunPreview();
document.getElementById('cs-preview-btn').textContent = '↺ Undo Preview';
}
});

// ── Core swap logic ───────────────────────────────────────
function csApplySwap(data) {
const t = CS.tolerance;
for (let i = 0; i < data.length; i += 4) {
if (data[i+3] < 1) continue;
if (Math.abs(data[i]   - CS.fromR) <= t &&
Math.abs(data[i+1] - CS.fromG) <= t &&
Math.abs(data[i+2] - CS.fromB) <= t) {
data[i]   = CS.toR;
data[i+1] = CS.toG;
data[i+2] = CS.toB;
}
}
}

// ── Apply button ──────────────────────────────────────────
document.getElementById('colorswap-apply').addEventListener('click', () => {
if (!S.current || S.currentKind !== 'image') return;
const al = activeLayer(); if (!al) return;

if (CS.previewActive) {
// Already applied to the layer — just commit
CS.previewActive   = false;
CS.previewSnapshot = null;
} else {
// Apply fresh swap to active layer
const id = al.ctx.getImageData(0, 0, al.canvas.width, al.canvas.height);
csApplySwap(id.data);
al.ctx.putImageData(id, 0, 0);
layerComposite();
}

pushHistory();
const n = document.getElementById('cs-preview-count').textContent;
toast(`Swapped ${n} pixels ✓`, 's');
document.getElementById('cs-preview-btn').textContent = '👁 Preview';
document.getElementById('colorswap-bg').classList.add('off');
});

// Initialize swatches on load
csSetFrom(255, 0, 0);
csSetTo(0, 255, 0);

/* ── LAYERS SYSTEM ───────────────────────────────────────── */

let _layerIdCtr = 0;

// Create a new layer object, optionally pre-filled with ImageData
function layerNew(name, imageData) {
const c   = document.createElement('canvas');
c.width   = MC.width  || 1;
c.height  = MC.height || 1;
const ctx = c.getContext('2d', { willReadFrequently: true });
if (imageData) ctx.putImageData(imageData, 0, 0);
return { id: ++_layerIdCtr, name: name || `Layer ${_layerIdCtr}`,
canvas: c, ctx, visible: true, opacity: 100,
blendMode: 'source-over', locked: false };
}

// Active layer helpers
function activeLayer()    { return S.layers[S.activeLayerIdx]; }
function activeLayerCtx() { const al = activeLayer(); return al ? al.ctx : MCX; }

// Flatten all visible layers onto MC for display
function layerComposite() {
MCX.clearRect(0, 0, MC.width, MC.height);
S.layers.forEach(l => {
if (!l.visible) return;
MCX.globalAlpha              = l.opacity / 100;
MCX.globalCompositeOperation = l.blendMode;
MCX.drawImage(l.canvas, 0, 0);
});
MCX.globalAlpha              = 1;
MCX.globalCompositeOperation = 'source-over';
refreshLayerThumbs();
}

// Flatten to an offscreen canvas for export (non-destructive)
function layerFlatCanvas() {
const fc  = document.createElement('canvas');
fc.width  = MC.width; fc.height = MC.height;
const fx  = fc.getContext('2d');
S.layers.forEach(l => {
if (!l.visible) return;
fx.globalAlpha              = l.opacity / 100;
fx.globalCompositeOperation = l.blendMode;
fx.drawImage(l.canvas, 0, 0);
});
fx.globalAlpha = 1; fx.globalCompositeOperation = 'source-over';
return fc;
}

// ── Layers panel UI ───────────────────────────────────────

function renderLayersPanel() {
const list = document.getElementById('layer-list');
list.innerHTML = '';
// Render top → bottom (reverse order)
for (let i = S.layers.length - 1; i >= 0; i--) {
const l   = S.layers[i];
const row = document.createElement('div');
row.className = 'layer-row' + (i === S.activeLayerIdx ? ' active' : '');
row.dataset.idx = i;

// Thumbnail
const thumb = document.createElement('canvas');
thumb.className = 'layer-thumb';
thumb.width = 24; thumb.height = 24;
drawLayerThumb(thumb, l);

// Visibility toggle
const vis = document.createElement('span');
vis.className = 'layer-vis' + (l.visible ? '' : ' hidden');
vis.textContent = '👁';
vis.title = l.visible ? 'Hide layer' : 'Show layer';
vis.addEventListener('click', e => {
e.stopPropagation();
l.visible = !l.visible;
layerComposite();
renderLayersPanel();
});

// Name (double-click to rename)
const nameEl = document.createElement('span');
nameEl.className = 'layer-name';
nameEl.textContent = l.name;
nameEl.title = 'Double-click to rename';
nameEl.addEventListener('dblclick', e => {
e.stopPropagation();
const input = document.createElement('input');
input.value = l.name;
input.style.cssText = 'flex:1;background:var(--bg);border:1px solid var(--blue);border-radius:3px;color:var(--text);font-family:var(--mono);font-size:11.5px;padding:1px 4px;outline:none;width:100%';
nameEl.replaceWith(input);
input.focus(); input.select();
const commit = () => { l.name = input.value.trim() || l.name; renderLayersPanel(); };
input.addEventListener('blur', commit);
input.addEventListener('keydown', e2 => { if (e2.key==='Enter') commit(); if (e2.key==='Escape') renderLayersPanel(); });
});

// Action buttons
const acts = document.createElement('div');
acts.className = 'layer-acts';

const mkBtn = (label, title, cls, handler) => {
const b = document.createElement('button');
b.className = 'layer-act-btn' + (cls ? ' '+cls : '');
b.textContent = label; b.title = title;
b.addEventListener('click', e => { e.stopPropagation(); handler(); });
return b;
};

acts.appendChild(mkBtn('↑', 'Move up',   '', () => layerMove(i, 1)));
acts.appendChild(mkBtn('↓', 'Move down', '', () => layerMove(i, -1)));
acts.appendChild(mkBtn('✕', 'Delete',  'del', () => layerDelete(i)));

row.appendChild(vis);
row.appendChild(thumb);
row.appendChild(nameEl);
row.appendChild(acts);
row.addEventListener('click', () => layerSelect(i));
list.appendChild(row);
}

// Sync opacity / blend for active layer
const al = activeLayer();
if (al) {
document.getElementById('layer-opacity').value = al.opacity;
document.getElementById('layer-opacity-v').textContent = al.opacity + '%';
document.getElementById('layer-blend').value = al.blendMode;
}
}

function drawLayerThumb(thumbCanvas, layer) {
const ctx = thumbCanvas.getContext('2d');
ctx.clearRect(0, 0, 24, 24);
ctx.drawImage(layer.canvas, 0, 0, 24, 24);
}

function refreshLayerThumbs() {
document.querySelectorAll('.layer-row').forEach(row => {
const i   = +row.dataset.idx;
const l   = S.layers[i];
if (!l) return;
const th  = row.querySelector('.layer-thumb');
if (th) drawLayerThumb(th, l);
});
}

// ── Layer operations ──────────────────────────────────────

function layerSelect(i) {
S.activeLayerIdx = Math.max(0, Math.min(S.layers.length - 1, i));
renderLayersPanel();
}

function layerMove(i, dir) {
const j = i + dir; // dir=1 moves up (higher index), dir=-1 moves down
if (j < 0 || j >= S.layers.length) return;
[S.layers[i], S.layers[j]] = [S.layers[j], S.layers[i]];
if (S.activeLayerIdx === i) S.activeLayerIdx = j;
else if (S.activeLayerIdx === j) S.activeLayerIdx = i;
layerComposite();
renderLayersPanel();
pushHistory();
}

function layerDelete(i) {
if (S.layers.length <= 1) { toast('Cannot delete the only layer', 'i', 2000); return; }
S.layers.splice(i, 1);
S.activeLayerIdx = Math.min(S.activeLayerIdx, S.layers.length - 1);
layerComposite();
renderLayersPanel();
pushHistory();
toast('Layer deleted', 'i', 2000);
}

function layerAdd() {
const l = layerNew(`Layer ${S.layers.length + 1}`);
S.layers.push(l);
S.activeLayerIdx = S.layers.length - 1;
layerComposite();
renderLayersPanel();
pushHistory();
}

function layerDuplicate() {
const al = activeLayer();
if (!al) return;
const data = al.ctx.getImageData(0, 0, al.canvas.width, al.canvas.height);
const dup  = layerNew(al.name + ' copy', data);
dup.opacity = al.opacity; dup.blendMode = al.blendMode; dup.visible = al.visible;
S.layers.splice(S.activeLayerIdx + 1, 0, dup);
S.activeLayerIdx = S.activeLayerIdx + 1;
layerComposite();
renderLayersPanel();
pushHistory();
toast('Layer duplicated', 's', 2000);
}

function layerMergeDown() {
const i = S.activeLayerIdx;
if (i === 0) { toast('No layer below to merge into', 'i', 2000); return; }
const top = S.layers[i], bot = S.layers[i - 1];
// Draw top onto bottom using top's blend/opacity
bot.ctx.globalAlpha              = top.opacity / 100;
bot.ctx.globalCompositeOperation = top.blendMode;
bot.ctx.drawImage(top.canvas, 0, 0);
bot.ctx.globalAlpha = 1; bot.ctx.globalCompositeOperation = 'source-over';
S.layers.splice(i, 1);
S.activeLayerIdx = i - 1;
layerComposite();
renderLayersPanel();
pushHistory();
toast('Layers merged', 's', 2000);
}

function layerFlattenAll() {
const fc  = layerFlatCanvas();
const fctx = fc.getContext('2d', { willReadFrequently: true });
const data = fctx.getImageData(0, 0, fc.width, fc.height);
_layerIdCtr = 0;
S.layers = [layerNew('Background', data)];
S.activeLayerIdx = 0;
layerComposite();
renderLayersPanel();
pushHistory();
toast('All layers flattened', 's', 2000);
}

// ── Layer property controls ───────────────────────────────

document.getElementById('layer-opacity').addEventListener('input', function() {
const al = activeLayer(); if (!al) return;
al.opacity = +this.value;
document.getElementById('layer-opacity-v').textContent = this.value + '%';
layerComposite();
});
document.getElementById('layer-opacity').addEventListener('change', () => pushHistory());

document.getElementById('layer-blend').addEventListener('change', function() {
const al = activeLayer(); if (!al) return;
al.blendMode = this.value;
layerComposite();
pushHistory();
});

document.getElementById('btn-layer-add')    .addEventListener('click', layerAdd);
document.getElementById('btn-layer-flatten').addEventListener('click', layerFlattenAll);
document.getElementById('btn-layer-dup')    .addEventListener('click', layerDuplicate);
document.getElementById('btn-layer-merge')  .addEventListener('click', layerMergeDown);

