// ── Core equirectangular → cubemap conversion ─────────────

function sampleEquirect(data, imgW, imgH, dx, dy, dz) {
const len = Math.sqrt(dx*dx + dy*dy + dz*dz);
const nx = dx/len, ny = dy/len, nz = dz/len;
const phi   = Math.atan2(nx, nz);
const theta = Math.acos(Math.max(-1, Math.min(1, ny)));
let u = (phi / (2 * Math.PI) + 0.5);
let v = theta / Math.PI;
u = ((u % 1) + 1) % 1;
v = Math.max(0, Math.min(1, v));
const px = Math.min(imgW - 1, Math.floor(u * imgW));
const py = Math.min(imgH - 1, Math.floor(v * imgH));
const i  = (py * imgW + px) * 4;
return [data[i], data[i+1], data[i+2], data[i+3]];
}

// Flat image mode: wrap image cylindrically around 4 sides, stretch top/bottom for up/down faces
function sampleFlat(data, imgW, imgH, faceIdx, pu, pv) {
// pu, pv = pixel-space 0–1 coords within the face (left→right, top→bottom)
let sx, sy;
switch (faceIdx) {
// 4 side faces each get one quarter of the image width, full height
case 4: sx = 0/4 + pu/4;         sy = pv; break; // South: leftmost quarter
case 0: sx = 1/4 + pu/4;         sy = pv; break; // East
case 5: sx = 2/4 + pu/4;         sy = pv; break; // North
case 1: sx = 3/4 + pu/4;         sy = pv; break; // West: rightmost quarter
// Up face: top strip of image, fanned outward from top edge
case 2: {
  const angle = pu * Math.PI * 2;
  const r = pv * 0.5; // 0 = centre, 0.5 = edge
  sx = ((Math.sin(angle) * r) + 0.5) * 0.5 + 0.25;
  sy = (1 - Math.cos(angle)) * r * 0.15; // sample near top
  break;
}
// Down face: bottom strip of image
case 3: {
  const angle = pu * Math.PI * 2;
  const r = pv * 0.5;
  sx = ((Math.sin(angle) * r) + 0.5) * 0.5 + 0.25;
  sy = 1 - (1 - Math.cos(angle)) * r * 0.15; // sample near bottom
  break;
}
default: sx = pu; sy = pv;
}
sx = ((sx % 1) + 1) % 1;
sy = Math.max(0, Math.min(1, sy));
const px2 = Math.min(imgW - 1, Math.floor(sx * imgW));
const py2 = Math.min(imgH - 1, Math.floor(sy * imgH));
const i = (py2 * imgW + px2) * 4;
return [data[i], data[i+1], data[i+2], data[i+3]];
}

function renderCubeFace(faceIdx, faceSize, srcData, imgW, imgH) {
const fc  = document.createElement('canvas');
fc.width  = fc.height = faceSize;
const fctx = fc.getContext('2d');
const out  = fctx.createImageData(faceSize, faceSize);
const d    = out.data;

for (let py = 0; py < faceSize; py++) {
for (let px = 0; px < faceSize; px++) {
const u = (px + 0.5) / faceSize;
const v = (py + 0.5) / faceSize;
let r, g, b2, al;
if (SBC_MODE === 'flat') {
[r, g, b2, al] = sampleFlat(srcData, imgW, imgH, faceIdx, u, v);
} else {
const a = u * 2 - 1;
const b = v * 2 - 1;
let dx, dy, dz;
switch (faceIdx) {
case 0: dx= 1; dy=-b; dz= a; break;
case 1: dx=-1; dy=-b; dz=-a; break;
case 2: dx= a; dy= 1; dz=-b; break;
case 3: dx=-a; dy=-1; dz= b; break;
case 4: dx=-a; dy=-b; dz= 1; break;
case 5: dx= a; dy=-b; dz=-1; break;
}
[r, g, b2, al] = sampleEquirect(srcData, imgW, imgH, dx, dy, dz);
}
const oi = (py * faceSize + px) * 4;
d[oi]=r; d[oi+1]=g; d[oi+2]=b2; d[oi+3]=al !== undefined ? al : 255;
}
}
fctx.putImageData(out, 0, 0);
return fc;
}

async function runSkyboxConvert(file) {
sbcShowStep('processing');
sbcResetLog();
document.getElementById('sbc-proc-icon').textContent  = '⚙️';
document.getElementById('sbc-proc-title').textContent = 'Loading image…';

try {
sbcLog('📷 Loading ' + file.name + '…');
sbcProgress(5);

// Load image into canvas to get pixel data
const bmp = await createImageBitmap(file);
const srcCvs = document.createElement('canvas');
srcCvs.width  = bmp.width;
srcCvs.height = bmp.height;
const srcCtx  = srcCvs.getContext('2d', { willReadFrequently: true });
srcCtx.drawImage(bmp, 0, 0);
bmp.close();
const imgData = srcCtx.getImageData(0, 0, srcCvs.width, srcCvs.height).data;

sbcLog(`✔ Image loaded — ${srcCvs.width}×${srcCvs.height}px`, 'ok');
sbcLog(`ℹ Mode: ${SBC_MODE === 'flat' ? 'Flat Image (cylindrical wrap)' : 'Panorama (equirectangular)'}`, 'info');
if (SBC_MODE === 'panorama' && srcCvs.width / srcCvs.height < 1.5) {
sbcLog('⚠ Image is not 2:1 ratio — consider switching to Flat Image mode for non-panoramas.');
}
sbcLog(`⚙ Rendering 6 faces at ${SBC_SIZE}×${SBC_SIZE}px…`);
sbcProgress(15);

// Render all 6 faces — yield between each so UI stays responsive
SBC_FACES = [];
for (let i = 0; i < 6; i++) {
await new Promise(r => setTimeout(r, 0)); // yield
sbcLog(`  Rendering ${FACE_LABELS[i].name} (${FACE_LABELS[i].label})…`);
SBC_FACES.push(renderCubeFace(i, SBC_SIZE, imgData, srcCvs.width, srcCvs.height));
sbcProgress(15 + Math.round(((i+1)/6) * 65));
}

sbcLog('📝 Generating manifest…');
sbcProgress(85);

// Build .mcpack zip
const packName = file.name.replace(/\.[^.]+$/, '');
SBC_PACK_NAME  = packName + '_skybox.mcpack';

const zip = new JSZip();
for (let i = 0; i < 6; i++) {
const pngBlob = await new Promise(r => SBC_FACES[i].toBlob(r, 'image/png'));
const ab = await pngBlob.arrayBuffer();
zip.file(`textures/environment/overworld_cubemap/${FACE_LABELS[i].name}.png`, new Uint8Array(ab));
}

const manifest = {
format_version: 2,
header: {
name: packName + ' Skybox',
description: 'Custom skybox generated from equirectangular panorama',
uuid: crypto.randomUUID(),
version: [1, 0, 0],
min_engine_version: [1, 16, 0]
},
modules: [{ type: 'resources', uuid: crypto.randomUUID(), version: [1, 0, 0] }]
};
zip.file('manifest.json', JSON.stringify(manifest, null, 2));

sbcProgress(95);
SBC_PACK_BLOB = await zip.generateAsync({ type: 'blob', compression: 'DEFLATE', compressionOptions: { level: 6 } });
sbcProgress(100);
sbcLog('✔ Done!', 'ok');

// Build result face grid
const grid = document.getElementById('sbc-face-grid');
grid.innerHTML = '';
SBC_FACES.forEach((fc, i) => {
const card  = document.createElement('div');
card.className = 'sbc-face-card';
const thumb = document.createElement('canvas');
thumb.width  = SBC_SIZE;
thumb.height = SBC_SIZE;
thumb.getContext('2d').drawImage(fc, 0, 0);
const lbl = document.createElement('div');
lbl.className   = 'sbc-face-label';
lbl.textContent = `${FACE_LABELS[i].name} · ${FACE_LABELS[i].label}`;
card.appendChild(thumb);
card.appendChild(lbl);
grid.appendChild(card);
});

document.getElementById('sbc-result-sub').textContent =
`6 cubemap faces rendered at ${SBC_SIZE}×${SBC_SIZE}px from "${file.name}". Download the .mcpack and apply it as a resource pack in Bedrock.`;

sbcShowStep('result');

} catch(e) {
sbcLog('✖ Error: ' + e.message, 'err');
document.getElementById('sbc-proc-icon').textContent  = '❌';
document.getElementById('sbc-proc-title').textContent = 'Conversion failed';
console.error('[SkyboxConverter]', e);
}
}

/* ── SKIN EDITOR ─────────────────────────────────────────── */

// ── State ──────────────────────────────────────────────────
const SK = {
  tool: 'pencil', zoom: 8,
  color: { r: 63, g: 185, b: 80, a: 255 },
  history: [], hIdx: -1,
  skinW: 64, skinH: 64,
  bgLight: false, skinType: 'steve',
  grid2d: false, grid3d: false,
  drawing: false, lastPx: null,
  _syncQueued: false,
};

// ── Three.js handles ───────────────────────────────────────
let SK_RENDERER = null, SK_SCENE = null, SK_CAMERA = null;
let SK_MODEL = null, SK_TEX = null, SK_RAF = null;
let SK_ROT_X = 0.15, SK_ROT_Y = 0;
let SK_DRAG = false, SK_LASTX = 0, SK_LASTY = 0;
let SK_OVERLAYS = {};
let SK_PARTS = {}; // base body part meshes
let SK_3D_GRID_LINES = null;
let SK_AB_CTRL = null; // AbortController for 3D canvas listeners

// ── Open / close ───────────────────────────────────────────
document.getElementById('misc-skin-editor').addEventListener('click', () => {
  document.getElementById('misc-panel').classList.remove('open');
  document.getElementById('skin-editor').classList.remove('off');
  // If user has a skin already loaded, restore straight to edit step
  if (SK.hasSavedSkin) {
    skShowStep('edit');
    document.getElementById('skin-download').disabled = false;
    skTeardown3D();
    setTimeout(skInit3D, 60);
  } else {
    skShowStep('drop');
  }
});

document.getElementById('skin-back').addEventListener('click', () => {
  document.getElementById('skin-editor').classList.add('off');
  skShowStep('drop');
  skTeardown3D();
  // Mark that a skin is in progress — don't wipe history so user can resume
  SK.hasSavedSkin = (SK.hIdx >= 0 && sk2d().width > 0);
  // Reset UI toggles only (not the skin canvas/history)
  document.getElementById('skin-3d-edit-btn').classList.remove('active');
  document.getElementById('skin-3d-edit-btn').textContent = '✏️ 3D Paint: OFF';
  document.getElementById('skin-grid-3d-btn').classList.remove('active');
  document.getElementById('skin-grid-3d-btn').textContent = '⊞ Grid: OFF';
  document.getElementById('skin-grid-2d-btn').classList.remove('on');
  document.getElementById('skin-grid-canvas').style.display = 'none';
  document.getElementById('skin-3d-canvas').classList.remove('paint-mode');
  document.getElementById('skin-3d-hint').textContent = '🖱 Drag to rotate · Scroll to zoom';
  SK.grid2d = false; SK.grid3d = false; SK._syncQueued = false;
  document.getElementById('skin-disable-overlays').textContent = '✕ Disable all overlays';
});

document.getElementById('skin-load-new').addEventListener('click', () => {
  SK.hasSavedSkin = false;
  document.getElementById('skin-file-input').click();
});

document.getElementById('skin-download').addEventListener('click', () => {
  const c = document.getElementById('skin-2d-canvas');
  c.toBlob(blob => {
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'skin_edited.png';
    a.click();
    setTimeout(() => URL.revokeObjectURL(a.href), 5000);
  }, 'image/png');
});

function skShowStep(step) {
  document.getElementById('skin-step-drop').classList.toggle('off', step !== 'drop');
  document.getElementById('skin-step-edit').classList.toggle('off', step !== 'edit');
}

// ── Drop zone ──────────────────────────────────────────────
const skDrop = document.getElementById('skin-drop-zone');
skDrop.addEventListener('click', () => document.getElementById('skin-file-input').click());
skDrop.addEventListener('dragover',  e => { e.preventDefault(); skDrop.classList.add('over'); });
skDrop.addEventListener('dragleave', () => skDrop.classList.remove('over'));
skDrop.addEventListener('drop', e => {
  e.preventDefault(); skDrop.classList.remove('over');
  if (e.dataTransfer.files[0]) skLoadSkin(e.dataTransfer.files[0]);
});
document.getElementById('skin-file-input').addEventListener('change', function() {
  if (this.files[0]) skLoadSkin(this.files[0]);
  this.value = '';
});

function skLoadSkin(file) {
  const reader = new FileReader();
  reader.onload = ev => {
    const img = new Image();
    img.onload = () => {
      if (img.width !== 64 || (img.height !== 64 && img.height !== 32)) {
        toast(`Invalid size: ${img.width}×${img.height}. Must be 64×64 or 64×32.`, 'e', 4000);
        return;
      }
      SK.skinW = img.width; SK.skinH = img.height;
      const c = document.getElementById('skin-2d-canvas');
      c.width = SK.skinW; c.height = SK.skinH;
      const ctx = c.getContext('2d', { willReadFrequently: true });
      ctx.clearRect(0, 0, SK.skinW, SK.skinH);
      ctx.drawImage(img, 0, 0);
      SK.history = [ctx.getImageData(0, 0, SK.skinW, SK.skinH)];
      SK.hIdx = 0;
      SK.hasSavedSkin = true;
      skShowStep('edit');
      document.getElementById('skin-download').disabled = false;
      skApplyZoom(8);
      skTeardown3D();
      setTimeout(skInit3D, 60);
    };
    img.onerror = () => toast('Failed to decode image.', 'e', 3000);
    img.src = ev.target.result;
  };
  reader.onerror = () => toast('Failed to read file.', 'e', 3000);
  reader.readAsDataURL(file);
}

// ── 2D canvas accessor ─────────────────────────────────────
function sk2d() { return document.getElementById('skin-2d-canvas'); }
function sk2dCtx() { return sk2d().getContext('2d', { willReadFrequently: true }); }

// ── Zoom & grid ────────────────────────────────────────────
function skApplyZoom(z, anchorX, anchorY) {
  const wrap = document.getElementById('skin-canvas-wrap');
  const oldZoom = SK.zoom;
  SK.zoom = Math.max(2, Math.min(16, z));
  const c = sk2d();
  c.style.width  = (SK.skinW * SK.zoom) + 'px';
  c.style.height = (SK.skinH * SK.zoom) + 'px';
  const gc = document.getElementById('skin-grid-canvas');
  gc.style.width  = c.style.width;
  gc.style.height = c.style.height;
  document.getElementById('skin-zoom-lbl').textContent = SK.zoom + '×';
  skDraw2dGrid();
  // If an anchor point is given (mouse position relative to wrap), keep that point fixed
  if (anchorX !== undefined && anchorY !== undefined) {
    const scale = SK.zoom / oldZoom;
    wrap.scrollLeft = (wrap.scrollLeft + anchorX) * scale - anchorX;
    wrap.scrollTop  = (wrap.scrollTop  + anchorY) * scale - anchorY;
  }
}
document.getElementById('skin-zoom-in') .addEventListener('click', () => skApplyZoom(SK.zoom * 2));
document.getElementById('skin-zoom-out').addEventListener('click', () => skApplyZoom(Math.max(2, Math.floor(SK.zoom / 2))));

// Scroll to zoom on the 2D canvas — zoom toward mouse cursor
document.getElementById('skin-canvas-wrap').addEventListener('wheel', e => {
  if (!SK.skinW) return;
  e.preventDefault();
  const wrap = document.getElementById('skin-canvas-wrap');
  const rect = wrap.getBoundingClientRect();
  const mx = e.clientX - rect.left; // mouse x relative to wrap
  const my = e.clientY - rect.top;
  const newZoom = e.deltaY < 0
    ? Math.min(16, SK.zoom * 2)
    : Math.max(2, Math.floor(SK.zoom / 2));
  if (newZoom !== SK.zoom) skApplyZoom(newZoom, mx, my);
}, { passive: false });

function skDraw2dGrid() {
  const gc = document.getElementById('skin-grid-canvas');
  if (!SK.grid2d || !SK.skinW || SK.zoom < 4) { gc.style.display = 'none'; return; }
  const w = SK.skinW * SK.zoom, h = SK.skinH * SK.zoom;
  gc.width = w; gc.height = h;
  gc.style.display = 'block';
  const ctx = gc.getContext('2d');
  ctx.clearRect(0, 0, w, h);
  ctx.strokeStyle = 'rgba(255,255,255,0.2)';
  ctx.lineWidth = 1;
  for (let x = 0; x <= SK.skinW; x++) { ctx.beginPath(); ctx.moveTo(x*SK.zoom,0); ctx.lineTo(x*SK.zoom,h); ctx.stroke(); }
  for (let y = 0; y <= SK.skinH; y++) { ctx.beginPath(); ctx.moveTo(0,y*SK.zoom); ctx.lineTo(w,y*SK.zoom); ctx.stroke(); }
}

document.getElementById('skin-grid-2d-btn').addEventListener('click', function() {
  SK.grid2d = !SK.grid2d;
  this.classList.toggle('on', SK.grid2d);
  skDraw2dGrid();
});
document.getElementById('skin-grid-3d-btn').addEventListener('click', function() {
  SK.grid3d = !SK.grid3d;
  this.classList.toggle('active', SK.grid3d);
  this.textContent = `⊞ Grid: ${SK.grid3d ? 'ON' : 'OFF'}`;
  skDraw3dGrid();
});

// ── Color ──────────────────────────────────────────────────
function skSetColor(r, g, b, a = 255) {
  SK.color = { r, g, b, a };
  const hex = '#' + [r,g,b].map(v => v.toString(16).padStart(2,'0')).join('');
  document.getElementById('skin-color-swatch').style.background = `rgba(${r},${g},${b},${a/255})`;
  document.getElementById('skin-color-native').value = hex;
  document.getElementById('skin-color-info').textContent = `rgba(${r},${g},${b},${a})`;
}
document.getElementById('skin-color-native').addEventListener('input', function() {
  const h = this.value.replace('#','');
  skSetColor(parseInt(h.slice(0,2),16), parseInt(h.slice(2,4),16), parseInt(h.slice(4,6),16));
});
skSetColor(63, 185, 80);

// ── Tools ──────────────────────────────────────────────────
['pencil','eraser','pick'].forEach(t => {
  document.getElementById(`skin-t-${t}`).addEventListener('click', () => {
    SK.tool = t; SK.lastPx = null;
    ['pencil','eraser','pick'].forEach(x =>
      document.getElementById(`skin-t-${x}`).classList.toggle('on', x === t));
  });
});

// ── 2D drawing ─────────────────────────────────────────────
function skGetPx(e) {
  const r = sk2d().getBoundingClientRect();
  const ex = e.touches ? e.touches[0].clientX : e.clientX;
  const ey = e.touches ? e.touches[0].clientY : e.clientY;
  return {
    x: Math.max(0, Math.min(SK.skinW-1, Math.floor((ex - r.left) / SK.zoom))),
    y: Math.max(0, Math.min(SK.skinH-1, Math.floor((ey - r.top)  / SK.zoom))),
  };
}

function skPaintPixel(x, y, ctx) {
  if (SK.tool === 'eraser') { ctx.clearRect(x, y, 1, 1); return; }
  const { r, g, b, a } = SK.color;
  ctx.fillStyle = `rgba(${r},${g},${b},${a/255})`;
  ctx.fillRect(x, y, 1, 1);
}

function sk2dStroke(e) {
  if (!SK.drawing) return;
  const ctx = sk2dCtx();
  const { x, y } = skGetPx(e);
  document.getElementById('skin-coord').textContent = `${x}, ${y}`;
  if (SK.tool === 'pick') return;
  if (SK.lastPx) {
    const dx = x - SK.lastPx.x, dy = y - SK.lastPx.y;
    const steps = Math.max(Math.abs(dx), Math.abs(dy));
    for (let s = 0; s <= steps; s++)
      skPaintPixel(Math.round(SK.lastPx.x + dx*s/steps), Math.round(SK.lastPx.y + dy*s/steps), ctx);
  } else {
    skPaintPixel(x, y, ctx);
  }
  SK.lastPx = { x, y };
  skSyncTex();
}

function skPushHistory() {
  if (!SK.skinW) return;
  const snap = sk2dCtx().getImageData(0, 0, SK.skinW, SK.skinH);
  SK.history = SK.history.slice(0, SK.hIdx + 1);
  SK.history.push(snap);
  if (SK.history.length > 30) SK.history.shift();
  SK.hIdx = SK.history.length - 1;
}

const sk2dEl = document.getElementById('skin-2d-canvas');
sk2dEl.addEventListener('mousedown', e => {
  e.preventDefault(); SK.drawing = true; SK.lastPx = null;
  const { x, y } = skGetPx(e);
  document.getElementById('skin-coord').textContent = `${x}, ${y}`;
  if (SK.tool === 'pick') {
    const p = sk2dCtx().getImageData(x, y, 1, 1).data;
    skSetColor(p[0], p[1], p[2], p[3]);
    SK.tool = 'pencil';
    ['pencil','eraser','pick'].forEach(t =>
      document.getElementById(`skin-t-${t}`).classList.toggle('on', t === 'pencil'));
    SK.drawing = false; return;
  }
  skPaintPixel(x, y, sk2dCtx()); skSyncTex();
});
sk2dEl.addEventListener('mousemove', e => sk2dStroke(e));
sk2dEl.addEventListener('mouseleave', () => { document.getElementById('skin-coord').textContent = '—'; });
sk2dEl.addEventListener('touchstart', e => { e.preventDefault(); SK.drawing = true; SK.lastPx = null; }, { passive: false });
sk2dEl.addEventListener('touchmove',  e => { e.preventDefault(); sk2dStroke(e); }, { passive: false });
sk2dEl.addEventListener('touchend',   () => { if (SK.drawing) skPushHistory(); SK.drawing = false; SK.lastPx = null; });

window.addEventListener('mouseup', () => {
  if (SK.drawing && (SK.tool === 'pencil' || SK.tool === 'eraser')) skPushHistory();
  SK.drawing = false; SK.lastPx = null;
});

document.getElementById('skin-undo-btn').addEventListener('click', () => {
  if (SK.hIdx <= 0) return;
  SK.hIdx--;
  sk2dCtx().putImageData(SK.history[SK.hIdx], 0, 0);
  skSyncTex();
});
document.getElementById('skin-redo-btn').addEventListener('click', () => {
  if (SK.hIdx >= SK.history.length - 1) return;
  SK.hIdx++;
  sk2dCtx().putImageData(SK.history[SK.hIdx], 0, 0);
  skSyncTex();
});

// ── Texture sync (debounced) ────────────────────────────────
function skSyncTex() {
  if (SK_TEX) SK_TEX.needsUpdate = true;
}

// ── UV helpers ─────────────────────────────────────────────
function skMakeBoxUVs(faces, flipSides) {
  const S = 64, arr = [];
  ['right','left','top','bottom','front','back'].forEach(name => {
    const [x, y, w, h] = faces[name];
    const u0 = x/S, u1 = (x+w)/S, v1 = 1-y/S, v0 = 1-(y+h)/S;
    if (flipSides && (name === 'right' || name === 'left'))
      arr.push(u1,v1, u0,v1, u1,v0, u0,v0);
    else if (name === 'bottom')
      // Bottom face (-Y) needs 180° rotation to match Minecraft's skin orientation
      arr.push(u1,v0, u0,v0, u1,v1, u0,v1);
    else
      arr.push(u0,v1, u1,v1, u0,v0, u1,v0);
  });
  return new Float32Array(arr);
}

function skPart(geo, uvFaces, flip = true) {
  geo.setAttribute('uv', new THREE.BufferAttribute(skMakeBoxUVs(uvFaces, flip), 2));
  return new THREE.Mesh(geo, new THREE.MeshLambertMaterial({
    map: SK_TEX, transparent: true, alphaTest: 0.1, side: THREE.FrontSide,
  }));
}

// ── Build 3D model ─────────────────────────────────────────
function skBuildModel() {
  const g = new THREE.Group();
  const P = skPart;
  const alex = SK.skinType === 'alex';
  const aw = alex ? 3 : 4;
  const O = 0.25;

  const parts = {};

  // HEAD
  parts.head = P(new THREE.BoxGeometry(8,8,8), {right:[0,8,8,8],left:[16,8,8,8],top:[8,0,8,8],bottom:[16,0,8,8],front:[8,8,8,8],back:[24,8,8,8]});
  parts.head.position.set(0,28,0);

  // BODY
  parts.body = P(new THREE.BoxGeometry(8,12,4), {right:[16,20,4,12],left:[28,20,4,12],top:[20,16,8,4],bottom:[28,16,8,4],front:[20,20,8,12],back:[32,20,8,12]});
  parts.body.position.set(0,18,0);

  // RIGHT ARM
  parts.rArm = P(new THREE.BoxGeometry(aw,12,4), alex
    ? {right:[48,20,4,12],left:[40,20,4,12],top:[44,16,3,4],bottom:[47,16,3,4],front:[44,20,3,12],back:[51,20,3,12]}
    : {right:[48,20,4,12],left:[40,20,4,12],top:[44,16,4,4],bottom:[48,16,4,4],front:[44,20,4,12],back:[52,20,4,12]}, false);
  parts.rArm.position.set(alex ? -5.5 : -6, 18, 0);

  // LEFT ARM
  parts.lArm = P(new THREE.BoxGeometry(aw,12,4), alex
    ? {right:[32,52,4,12],left:[40,52,4,12],top:[36,48,3,4],bottom:[39,48,3,4],front:[36,52,3,12],back:[43,52,3,12]}
    : {right:[32,52,4,12],left:[40,52,4,12],top:[36,48,4,4],bottom:[40,48,4,4],front:[36,52,4,12],back:[44,52,4,12]});
  parts.lArm.position.set(alex ? 5.5 : 6, 18, 0);

  // RIGHT LEG
  parts.rLeg = P(new THREE.BoxGeometry(4,12,4), {right:[8,20,4,12],left:[0,20,4,12],top:[4,16,4,4],bottom:[8,16,4,4],front:[4,20,4,12],back:[12,20,4,12]}, false);
  parts.rLeg.position.set(-2,6,0);

  // LEFT LEG
  parts.lLeg = P(new THREE.BoxGeometry(4,12,4), {right:[16,52,4,12],left:[24,52,4,12],top:[20,48,4,4],bottom:[24,48,4,4],front:[20,52,4,12],back:[28,52,4,12]});
  parts.lLeg.position.set(2,6,0);

  // ── OVERLAYS ──
  // HAT
  parts.hat = P(new THREE.BoxGeometry(8+O*2,8+O*2,8+O*2), {right:[32,8,8,8],left:[48,8,8,8],top:[40,0,8,8],bottom:[48,0,8,8],front:[40,8,8,8],back:[56,8,8,8]});
  parts.hat.position.set(0,28,0);

  // JACKET
  parts.jacket = P(new THREE.BoxGeometry(8+O*2,12+O*2,4+O*2), {right:[16,36,4,12],left:[28,36,4,12],top:[20,32,8,4],bottom:[28,32,8,4],front:[20,36,8,12],back:[32,36,8,12]});
  parts.jacket.position.set(0,18,0);

  // RIGHT ARM OVERLAY
  parts.rArmOv = P(new THREE.BoxGeometry(aw+O*2,12+O*2,4+O*2), alex
    ? {right:[48,36,4,12],left:[40,36,4,12],top:[44,32,3,4],bottom:[47,32,3,4],front:[44,36,3,12],back:[51,36,3,12]}
    : {right:[48,36,4,12],left:[40,36,4,12],top:[44,32,4,4],bottom:[48,32,4,4],front:[44,36,4,12],back:[52,36,4,12]}, false);
  parts.rArmOv.position.set(alex ? -5.5 : -6, 18, 0);

  // LEFT ARM OVERLAY
  parts.lArmOv = P(new THREE.BoxGeometry(aw+O*2,12+O*2,4+O*2), alex
    ? {right:[48,52,4,12],left:[56,52,4,12],top:[52,48,3,4],bottom:[55,48,3,4],front:[52,52,3,12],back:[59,52,3,12]}
    : {right:[48,52,4,12],left:[56,52,4,12],top:[52,48,4,4],bottom:[56,48,4,4],front:[52,52,4,12],back:[60,52,4,12]});
  parts.lArmOv.position.set(alex ? 5.5 : 6, 18, 0);

  // RIGHT LEG OVERLAY
  parts.rLegOv = P(new THREE.BoxGeometry(4+O*2,12+O*2,4+O*2), {right:[8,36,4,12],left:[0,36,4,12],top:[4,32,4,4],bottom:[8,32,4,4],front:[4,36,4,12],back:[12,36,4,12]}, false);
  parts.rLegOv.position.set(-2,6,0);

  // LEFT LEG OVERLAY
  parts.lLegOv = P(new THREE.BoxGeometry(4+O*2,12+O*2,4+O*2), {right:[0,52,4,12],left:[8,52,4,12],top:[4,48,4,4],bottom:[8,48,4,4],front:[4,52,4,12],back:[12,52,4,12]});
  parts.lLegOv.position.set(2,6,0);

  SK_OVERLAYS = { hat: parts.hat, jacket: parts.jacket, rArmOv: parts.rArmOv, lArmOv: parts.lArmOv, rLegOv: parts.rLegOv, lLegOv: parts.lLegOv };
  SK_PARTS    = { head: parts.head, body: parts.body, rArm: parts.rArm, lArm: parts.lArm, rLeg: parts.rLeg, lLeg: parts.lLeg };

  // Apply current checkbox states to base parts
  document.querySelectorAll('.skin-base-cb').forEach(cb => {
    const m = SK_PARTS[cb.dataset.part];
    if (m) m.visible = cb.checked;
  });

  // Apply current overlay checkbox states
  document.querySelectorAll('.skin-ov-cb').forEach(cb => {
    const m = SK_OVERLAYS[cb.dataset.ov];
    if (m) m.visible = cb.checked;
  });

  Object.values(parts).forEach(m => g.add(m));
  return g;
}

// ── 3D grid ────────────────────────────────────────────────
function skDraw3dGrid() {
  if (SK_3D_GRID_LINES) { SK_3D_GRID_LINES.parent && SK_3D_GRID_LINES.parent.remove(SK_3D_GRID_LINES); SK_3D_GRID_LINES = null; }
  if (!SK.grid3d || !SK_MODEL) return;
  const verts = [], S = 64;
  SK_MODEL.traverse(mesh => {
    if (!mesh.isMesh || !mesh.visible) return;
    const geo = mesh.geometry;
    const uvA = geo.getAttribute('uv'), posA = geo.getAttribute('position'), idx = geo.getIndex();
    if (!uvA || !posA || !idx) return;
    const ox = mesh.position.x, oy = mesh.position.y, oz = mesh.position.z;
    for (let i = 0; i < idx.count; i += 3) {
      const ia = idx.getX(i), ib = idx.getX(i+1), ic = idx.getX(i+2);
      const uvs = [ia,ib,ic].map(j => ({ u: uvA.getX(j), v: uvA.getY(j) }));
      const pos = [ia,ib,ic].map(j => ({ x: posA.getX(j)+ox, y: posA.getY(j)+oy, z: posA.getZ(j)+oz }));
      const uMin = Math.min(...uvs.map(p=>p.u)), uMax = Math.max(...uvs.map(p=>p.u));
      const vMin = Math.min(...uvs.map(p=>p.v)), vMax = Math.max(...uvs.map(p=>p.v));
      const pxMin = Math.floor(uMin*S), pxMax = Math.ceil(uMax*S);
      const pyMin = Math.floor(vMin*S), pyMax = Math.ceil(vMax*S);
      const bary = (u,v) => {
        const [u0,u1,u2]=[uvs[0].u,uvs[1].u,uvs[2].u],[v0,v1,v2]=[uvs[0].v,uvs[1].v,uvs[2].v];
        const d=(v1-v2)*(u0-u2)+(u2-u1)*(v0-v2);
        if (Math.abs(d)<1e-8) return pos[0];
        const w0=((v1-v2)*(u-u2)+(u2-u1)*(v-v2))/d, w1=((v2-v0)*(u-u2)+(u0-u2)*(v-v2))/d, w2=1-w0-w1;
        return {x:pos[0].x*w0+pos[1].x*w1+pos[2].x*w2, y:pos[0].y*w0+pos[1].y*w1+pos[2].y*w2, z:pos[0].z*w0+pos[1].z*w1+pos[2].z*w2};
      };
      for (let px=pxMin+1;px<=pxMax-1;px++){const u=px/S;if(u<uMin||u>uMax)continue;const a=bary(u,Math.max(vMin,pyMin/S)),b=bary(u,Math.min(vMax,pyMax/S));verts.push(a.x,a.y,a.z,b.x,b.y,b.z);}
      for (let py=pyMin+1;py<=pyMax-1;py++){const v=py/S;if(v<vMin||v>vMax)continue;const a=bary(Math.max(uMin,pxMin/S),v),b=bary(Math.min(uMax,pxMax/S),v);verts.push(a.x,a.y,a.z,b.x,b.y,b.z);}
    }
  });
  if (!verts.length) return;
  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.Float32BufferAttribute(verts, 3));
  SK_3D_GRID_LINES = new THREE.LineSegments(geo, new THREE.LineBasicMaterial({ color: 0xffffff, opacity: 0.25, transparent: true }));
  SK_MODEL.add(SK_3D_GRID_LINES);
}

// ── 3D init / teardown ─────────────────────────────────────
function skTeardown3D() {
  if (SK_AB_CTRL) { SK_AB_CTRL.abort(); SK_AB_CTRL = null; }
  if (SK_RAF) { cancelAnimationFrame(SK_RAF); SK_RAF = null; }
  if (SK_RENDERER) { if (SK_RENDERER._ro) SK_RENDERER._ro.disconnect(); SK_RENDERER.dispose(); SK_RENDERER = null; }
  SK_SCENE = SK_CAMERA = SK_MODEL = SK_TEX = null;
  SK_3D_GRID_LINES = null; SK_OVERLAYS = {}; SK_PARTS = {};
}

function skInit3D() {
  skTeardown3D();
  SK_AB_CTRL = new AbortController();
  const sig = SK_AB_CTRL.signal;

  const container = document.getElementById('skin-3d-panel');
  const cv = document.getElementById('skin-3d-canvas');

  SK_RENDERER = new THREE.WebGLRenderer({ canvas: cv, antialias: true, alpha: true });
  SK_RENDERER.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  SK_RENDERER.setSize(container.clientWidth, container.clientHeight);
  SK_RENDERER.setClearColor(SK.bgLight ? 0xcccccc : 0x0a0c10, 1);

  SK_SCENE  = new THREE.Scene();
  SK_CAMERA = new THREE.PerspectiveCamera(45, container.clientWidth / container.clientHeight, 0.1, 1000);
  SK_CAMERA.position.set(0, 16, 60);
  SK_CAMERA.lookAt(0, 16, 0);

  SK_SCENE.add(new THREE.AmbientLight(0xffffff, 0.8));
  const dir = new THREE.DirectionalLight(0xffffff, 0.6);
  dir.position.set(10, 20, 10);
  SK_SCENE.add(dir);

  SK_TEX = new THREE.CanvasTexture(sk2d());
  SK_TEX.magFilter = THREE.NearestFilter;
  SK_TEX.minFilter = THREE.NearestFilter;

  SK_MODEL = skBuildModel();
  SK_MODEL.position.set(0, -16, 0);
  SK_SCENE.add(SK_MODEL);
  skDraw3dGrid();

  SK_ROT_X = 0.15; SK_ROT_Y = 0;

  // Render loop
  (function loop() {
    SK_RAF = requestAnimationFrame(loop);
    SK_MODEL.rotation.x = SK_ROT_X;
    SK_MODEL.rotation.y = SK_ROT_Y;
    if (SK_TEX) SK_TEX.needsUpdate = true;
    SK_RENDERER.render(SK_SCENE, SK_CAMERA);
  })();

  // Resize
  const ro = new ResizeObserver(() => {
    if (!SK_RENDERER || !SK_CAMERA) return;
    SK_RENDERER.setSize(container.clientWidth, container.clientHeight);
    SK_CAMERA.aspect = container.clientWidth / container.clientHeight;
    SK_CAMERA.updateProjectionMatrix();
  });
  ro.observe(container);
  SK_RENDERER._ro = ro;

  // ── Raycaster (local to skInit3D — valid camera guaranteed) ──
  const ray = new THREE.Raycaster();

  function getNDC(e) {
    const r = cv.getBoundingClientRect();
    const cx = e.touches ? e.touches[0].clientX : e.clientX;
    const cy = e.touches ? e.touches[0].clientY : e.clientY;
    return { x: ((cx-r.left)/r.width)*2-1, y: ((cy-r.top)/r.height)*-2+1 };
  }

  // Cached list of visible meshes for raycasting
  let paintMeshes = [];
  function rebuildPaintMeshes() {
    paintMeshes = [];
    if (SK_MODEL) SK_MODEL.traverse(c => { if (c.isMesh && c.visible && c !== SK_3D_GRID_LINES) paintMeshes.push(c); });
  }
  rebuildPaintMeshes();

  let paint3d = false, painting = false;

  function doPaint(e) {
    const ndc = getNDC(e);
    ray.setFromCamera(ndc, SK_CAMERA);
    const hits = ray.intersectObjects(paintMeshes, false);
    if (!hits.length) return;
    const uv = hits[0].uv;
    if (!uv) return;
    const ctx = sk2dCtx();
    const px = Math.floor(uv.x * SK.skinW);
    const py = Math.floor((1 - uv.y) * SK.skinH);
    if (px < 0 || px >= SK.skinW || py < 0 || py >= SK.skinH) return;
    if (SK.tool === 'eraser') {
      ctx.clearRect(px, py, 1, 1);
    } else if (SK.tool === 'pick') {
      const p = ctx.getImageData(px, py, 1, 1).data;
      skSetColor(p[0], p[1], p[2], p[3]);
      SK.tool = 'pencil';
      ['pencil','eraser','pick'].forEach(t => document.getElementById(`skin-t-${t}`).classList.toggle('on', t === 'pencil'));
    } else {
      const { r, g, b, a } = SK.color;
      ctx.fillStyle = `rgba(${r},${g},${b},${a/255})`;
      ctx.fillRect(px, py, 1, 1);
    }
    skSyncTex();
  }

  cv.addEventListener('mousedown', e => {
    if (paint3d) { painting = true; doPaint(e); }
    else { SK_DRAG = true; SK_LASTX = e.clientX; SK_LASTY = e.clientY; }
  }, { signal: sig });

  cv.addEventListener('mousemove', e => {
    if (paint3d && painting) doPaint(e);
    else if (!paint3d && SK_DRAG) {
      SK_ROT_Y += (e.clientX - SK_LASTX) * 0.01;
      SK_ROT_X += (e.clientY - SK_LASTY) * 0.01;
      SK_ROT_X = Math.max(-Math.PI/2, Math.min(Math.PI/2, SK_ROT_X));
      SK_LASTX = e.clientX; SK_LASTY = e.clientY;
    }
  }, { signal: sig });

  window.addEventListener('mouseup', () => {
    if (painting) { skPushHistory(); painting = false; }
    SK_DRAG = false;
  }, { signal: sig });

  cv.addEventListener('touchstart', e => {
    if (paint3d) { painting = true; doPaint(e); }
    else { SK_DRAG = true; SK_LASTX = e.touches[0].clientX; SK_LASTY = e.touches[0].clientY; }
  }, { passive: true, signal: sig });

  cv.addEventListener('touchmove', e => {
    if (paint3d && painting) doPaint(e);
    else if (!paint3d && SK_DRAG) {
      SK_ROT_Y += (e.touches[0].clientX - SK_LASTX) * 0.012;
      SK_ROT_X += (e.touches[0].clientY - SK_LASTY) * 0.012;
      SK_ROT_X = Math.max(-Math.PI/2, Math.min(Math.PI/2, SK_ROT_X));
      SK_LASTX = e.touches[0].clientX; SK_LASTY = e.touches[0].clientY;
    }
  }, { passive: true, signal: sig });

  cv.addEventListener('touchend', () => {
    if (painting) { skPushHistory(); painting = false; }
    SK_DRAG = false;
  }, { signal: sig });

  cv.addEventListener('wheel', e => {
    e.preventDefault();
    const delta = e.deltaY * 0.1;
    const newZ = Math.max(20, Math.min(120, SK_CAMERA.position.z + delta));
    // Zoom toward the point under the cursor, not just straight in/out
    const ndc = getNDC(e);
    const vec = new THREE.Vector3(ndc.x, ndc.y, 0.5).unproject(SK_CAMERA);
    vec.sub(SK_CAMERA.position).normalize();
    const moveDist = SK_CAMERA.position.z - newZ;
    SK_CAMERA.position.addScaledVector(vec, moveDist);
    // Clamp Z so model stays in view
    SK_CAMERA.position.z = Math.max(20, Math.min(120, SK_CAMERA.position.z));
  }, { passive: false, signal: sig });

  // 3D paint toggle
  document.getElementById('skin-3d-edit-btn').addEventListener('click', function() {
    paint3d = !paint3d;
    rebuildPaintMeshes();
    this.classList.toggle('active', paint3d);
    this.textContent = `✏️ 3D Paint: ${paint3d ? 'ON' : 'OFF'}`;
    cv.classList.toggle('paint-mode', paint3d);
    document.getElementById('skin-3d-hint').textContent = paint3d
      ? '✏️ Click/drag to paint · Scroll to zoom'
      : '🖱 Drag to rotate · Scroll to zoom';
  }, { signal: sig });

  // Base part checkboxes
  document.querySelectorAll('.skin-base-cb').forEach(cb => {
    cb.addEventListener('change', () => {
      const m = SK_PARTS[cb.dataset.part];
      if (m) m.visible = cb.checked;
      rebuildPaintMeshes();
      skDraw3dGrid();
    }, { signal: sig });
  });

  // Overlay checkboxes
  document.querySelectorAll('.skin-ov-cb').forEach(cb => {
    cb.addEventListener('change', () => {
      const m = SK_OVERLAYS[cb.dataset.ov];
      if (m) m.visible = cb.checked;
      rebuildPaintMeshes();
      skDraw3dGrid();
    }, { signal: sig });
  });

  // Disable / re-enable all overlays button
  document.getElementById('skin-disable-overlays').addEventListener('click', () => {
    const cbs = document.querySelectorAll('.skin-ov-cb');
    const anyOn = Array.from(cbs).some(cb => cb.checked);
    cbs.forEach(cb => {
      cb.checked = !anyOn;
      const m = SK_OVERLAYS[cb.dataset.ov];
      if (m) m.visible = !anyOn;
    });
    document.getElementById('skin-disable-overlays').textContent =
      anyOn ? '✓ Re-enable all overlays' : '✕ Disable all overlays';
    rebuildPaintMeshes();
    skDraw3dGrid();
  }, { signal: sig });
}

// ── Steve / Alex toggle ────────────────────────────────────
function skSetType(type) {
  SK.skinType = type;
  const sb = document.getElementById('skin-type-steve');
  const ab = document.getElementById('skin-type-alex');
  sb.style.background = type === 'steve' ? 'var(--green)' : 'transparent';
  sb.style.color      = type === 'steve' ? '#fff' : 'var(--muted)';
  ab.style.background = type === 'alex'  ? 'var(--green)' : 'transparent';
  ab.style.color      = type === 'alex'  ? '#fff' : 'var(--muted)';
  if (SK_SCENE && SK_MODEL) {
    if (SK_3D_GRID_LINES && SK_3D_GRID_LINES.parent) SK_3D_GRID_LINES.parent.remove(SK_3D_GRID_LINES);
    SK_3D_GRID_LINES = null;
    SK_SCENE.remove(SK_MODEL);
    SK_MODEL = skBuildModel();
    SK_MODEL.position.set(0, -16, 0);
    SK_SCENE.add(SK_MODEL);
    skDraw3dGrid();
  }
}
document.getElementById('skin-type-steve').addEventListener('click', () => skSetType('steve'));
document.getElementById('skin-type-alex') .addEventListener('click', () => skSetType('alex'));

// ── BG toggle ──────────────────────────────────────────────
document.getElementById('skin-bg-btn').addEventListener('click', function() {
  SK.bgLight = !SK.bgLight;
  this.textContent = SK.bgLight ? '☀️ Light BG' : '🌑 Dark BG';
  if (SK_RENDERER) SK_RENDERER.setClearColor(SK.bgLight ? 0xcccccc : 0x0a0c10, 1);
});



/* ── SKIN 2D PANEL RESIZE ─────────────────────────────────── */
(function() {
  const handle = document.getElementById('skin-2d-resize-handle');
  const panel  = document.getElementById('skin-2d-panel');
  let dragging = false, startX = 0, startW = 0;

  handle.addEventListener('mousedown', e => {
    dragging = true;
    startX   = e.clientX;
    startW   = panel.offsetWidth;
    handle.classList.add('dragging');
    document.body.style.cursor    = 'col-resize';
    document.body.style.userSelect = 'none';
    e.preventDefault();
  });

  document.addEventListener('mousemove', e => {
    if (!dragging) return;
    // Handle is on the LEFT edge of the panel, so dragging left = wider
    const delta = startX - e.clientX;
    const minW  = parseInt(getComputedStyle(panel).minWidth) || 180;
    const maxW  = Math.floor(window.innerWidth * 0.7);
    panel.style.width = Math.min(maxW, Math.max(minW, startW + delta)) + 'px';
  });

  document.addEventListener('mouseup', () => {
    if (!dragging) return;
    dragging = false;
    handle.classList.remove('dragging');
    document.body.style.cursor     = '';
    document.body.style.userSelect = '';
  });

  // Touch support
  handle.addEventListener('touchstart', e => {
    const t = e.touches[0];
    dragging = true; startX = t.clientX; startW = panel.offsetWidth;
    handle.classList.add('dragging');
    e.preventDefault();
  }, {passive:false});

  document.addEventListener('touchmove', e => {
    if (!dragging) return;
    const t     = e.touches[0];
    const delta = startX - t.clientX;
    const minW  = parseInt(getComputedStyle(panel).minWidth) || 180;
    const maxW  = Math.floor(window.innerWidth * 0.7);
    panel.style.width = Math.min(maxW, Math.max(minW, startW + delta)) + 'px';
  }, {passive:true});

  document.addEventListener('touchend', () => {
    dragging = false; handle.classList.remove('dragging');
  });
})();

/* ── INIT ─────────────────────────────────────────────────── */
setColor(63,185,80,255);

try {
/* ── Ripple effect on all buttons ── */
document.addEventListener('mousedown', function(e) {
  const btn = e.target.closest('button');
  if (!btn || btn.disabled) return;
  const rect = btn.getBoundingClientRect();
  const rx = ((e.clientX - rect.left) / rect.width * 100).toFixed(1) + '%';
  const ry = ((e.clientY - rect.top)  / rect.height * 100).toFixed(1) + '%';
  btn.style.setProperty('--rx', rx);
  btn.style.setProperty('--ry', ry);
  btn.classList.remove('rippling');
  void btn.offsetWidth; /* reflow */
  btn.classList.add('rippling');
  const done = () => btn.classList.remove('rippling');
  btn.addEventListener('animationend', done, { once: true });
  setTimeout(done, 600);
});
} catch (_e) { console.error(_e); }

/* expose ADJ_ORIG for the inline preview script */
function getAdjOrig() { return ADJ_ORIG; }

